(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).ar = [
  { id:1, topic:"ماء آمن", emoji:"💧",
    question:"أي ماء آمن ولا يسبب لك ألمًا في البطن؟",
    choices:["ماء النهر","ماء البئر","ماء غُلي جيدًا على النار","ماء المطر"],
    answerIndex:2,
    explanation:"قد يبدو ماء النهر والبئر والمطر صافيًا ونظيفًا تمامًا، لكنه قد يكون مليئًا بكائنات حية صغيرة جدًا لا تراها أعيننا (جراثيم وفيروسات). وإذا شربت هذا الماء كما هو، فقد يسبب ألمًا شديدًا في المعدة أو مرضًا خطيرًا يهدّد الحياة. لكن عندما تضع الماء على النار وتغليه بقوة حتى تتصاعد الفقاعات، تقتل الحرارة كل تلك الكائنات الضارة. لهذا فإن الماء الذي غُلي جيدًا ثم تُرك ليبرد هو أأمن ماء في العالم، وهو الماء الذي يمكنك شربه باطمئنان." },
  { id:2, topic:"غسل اليدين", emoji:"🧼",
    question:"ماذا يجب أن تفعل قبل الأكل؟",
    choices:["تغسل يديك بالماء والصابون","تمسح يديك بملابسك","لا تفعل شيئًا","تلمس التراب"],
    answerIndex:0,
    explanation:"تلمس أيدينا أشياء كثيرة وتلمس الأرض كل يوم، فتحمل دون أن نشعر الكثير من الجراثيم غير المرئية. وإذا لمست الطعام بهذه اليدين، تنتقل الجراثيم إلى الطعام وتبتلعها إلى داخل جسمك مع الطعام. ومسح اليدين بملابس متّسخة أو مجرّد بلّهما بالماء لا يزيل الجراثيم؛ فهي تبقى عالقة. ولا يمكنك إزالة الجراثيم حقًا إلا باستخدام الصابون وفرك راحتَي اليدين وظهرهما وما بين الأصابع برغوة جيدة، ثم الشطف بالماء." },
  { id:3, topic:"غسل اليدين", emoji:"🚽",
    question:"ماذا يجب أن تفعل بعد دخول المرحاض؟",
    choices:["تذهب للّعب فورًا","تغسل يديك بالماء والصابون","تفرك يديك بملابسك","تجفّف يديك بالسروال"],
    answerIndex:1,
    explanation:"بعد دخول المرحاض، تعلق بيديك بسهولة جراثيم قوية جدًا من البراز والبول تسبّب الأمراض. وإذا ذهبت للّعب دون غسل يديك، تنتقل هذه الجراثيم إلى مقابض الأبواب والألعاب التي تلمسها، فتنقل المرض إلى الصديق أو أحد أفراد العائلة الذي يلمسها بعدك. وإذا لمست فمك أو عينيك بهذه اليدين، فقد تمرض أنت أيضًا. ومهما كنت مستعجلًا، فإن غسل يديك دائمًا جيدًا بالماء والصابون بعد المرحاض قاعدة تحمي حياتك وحياة من حولك." },
  { id:4, topic:"الصحة", emoji:"💧",
    question:"عندما تتألم بطنك ويصبح البراز سائلًا (الإسهال)، ما الأهم؟",
    choices:["أن تأكل كثيرًا","ألّا تشرب شيئًا","أن تشرب كثيرًا من الماء الآمن","أن تركض وتلعب"],
    answerIndex:2,
    explanation:"عندما تتألم بطنك ويخرج براز سائل (إسهال) مرة بعد مرة، يفقد جسمك ماءً وغذاءً ثمينًا باستمرار. وهذا يسمّى الجفاف. وعندما ينقص الماء في الجسم، تبدأ الوظائف المهمة التي تبقينا أحياء بالتوقف، وقد يفقد الأطفال الصغار خاصة حياتهم فجأة. وعند الإسهال، بدل أن ترغم نفسك على أكل الطعام الصلب، الأفضل أولًا أن تعوّض الماء الذي فقدته. وبشرب الماء الآمن المغلي والمبرّد، قليلًا قليلًا ومرات كثيرة، يمكنك أن تحافظ على قوتك وتحمي حياتك." },
  { id:5, topic:"علاج الجروح", emoji:"🩹",
    question:"عندما تقع وتنزف، ماذا تفعل أولًا؟",
    choices:["تضع عليه ترابًا","تغسله جيدًا بماء نظيف","تتركه دون فعل شيء","تفركه بورقة شجر"],
    answerIndex:1,
    explanation:"عندما تقع وتُصاب بجرح ينزف، يكون الجرح مغطًّى بالتراب والطين والغبار من الأرض، مع الكثير من الجراثيم. وإذا صدّقت الأقوال القديمة ووضعت عليه ترابًا، أو فركته بورقة متّسخة، أو تركته هكذا، تدخل الجراثيم عميقًا في الجرح وتتكاثر. عندها يتورّم الجرح ويحمرّ ويؤلم بشدة، وفي أسوأ الحالات قد تتعفّن اليد أو الرجل وتتوقف عن الحركة. وعندما تُصاب، فإن أول خطوة صحيحة كي لا يصبح الجرح خطيرًا هي استخدام ماء نظيف وآمن قريب لغسل الطين والوسخ عن الجرح بقوة." },
  { id:6, topic:"الطعام", emoji:"🦠",
    question:"ماذا يحدث عندما يفسد الطعام (يتعفّن)؟",
    choices:["يصبح لذيذًا","يتعفّن ويسبّب ألم البطن","يصبح قاسيًا","لا يتغيّر شيء"],
    answerIndex:1,
    explanation:"يحتوي الطعام بطبيعته منذ البداية على عدد قليل من الميكروبات غير المرئية. في مكان بارد لا تستطيع الميكروبات أن تنشط، لكن إذا تركت الطعام وقتًا طويلًا في مكان دافئ وحار، يصبح بيئة مثالية لها، وفي ساعات قليلة تتكاثر إلى الملايين، وهو عدد مخيف. وعندما تتكاثر الميكروبات بهذا القدر ويتغيّر شكل الطعام وطبيعته، نقول إنه فسد. والطعام الفاسد يحمل السمّ القوي الذي صنعته الميكروبات، فأكله يسبّب ألمًا شديدًا في المعدة وإسهالًا وغثيانًا، ويضرّ جسمك." },
  { id:7, topic:"الطعام", emoji:"👃",
    question:"ما علامة أن الطعام قد فسد؟",
    choices:["رائحة أو طعم غريب","لون أحمر","شيء بارد","شيء مطهوّ جيدًا"],
    answerIndex:0,
    explanation:"يمكنك أن تستخدم أنفك ولسانك للتحقق مما إذا كان الطعام قد فسد ولم يعد آمنًا. فإذا كانت له رائحة حامضة غير معتادة أو رائحة حادة كريهة، أو طعم غريب عندما تضع قليلًا منه في فمك، أو إذا كان لزجًا ويمتدّ كالخيوط، فهذا دليل على أن الجراثيم تكاثرت كثيرًا وتكوّن السمّ. وإذا أرغمت نفسك على أكله لأنه «حرام أن يُرمى»، فإنك تعرّض حياتك للخطر بتسمّم شديد. فإذا كانت الرائحة أو الطعم مريبًا ولو قليلًا، فاتّخذ قرار رميه ولا تبتلعه أبدًا." },
  { id:8, topic:"الطعام", emoji:"🪰",
    question:"ماذا تفعل بالطعام الذي حطّ عليه ذباب؟",
    choices:["تأكله كما هو","لا تأكل الجزء الذي لمسه الذباب (ترميه)","تربّي الذبابة","تنظر إليه فقط"],
    answerIndex:1,
    explanation:"الحشرة التي نسمّيها الذباب تحب التجوّل في أماكن قذرة جدًا ومليئة بالجراثيم، مثل فضلات الحيوانات والجِيَف ومكبّات النفايات. ولهذا تعلق جراثيم تسبّب أمراضًا مخيفة بأرجلها الدقيقة وجسمها. وعندما تحطّ ذبابة كهذه على طعامنا، تنتقل في تلك اللحظة جراثيم أرجلها إلى الطعام. وإذا أكلت المكان الذي لمسته، فأنت تُدخل إلى فمك بشكل غير مباشر جراثيم الفضلات والنفايات، وهذا قد يسبّب مرضًا خطيرًا. ومع أن الأمر قد يبدو إهدارًا، فالأأمن أن تقطع وترمي الجزء الذي حطّ عليه الذباب." },
  { id:9, topic:"الوقاية من الأمراض", emoji:"🦟",
    question:"ماذا يحدث إذا تركت الماء راكدًا وقتًا طويلًا؟",
    choices:["يصبح الماء نظيفًا","يتكاثر البعوض الضار","يزيد مالك","لا يحدث شيء"],
    answerIndex:1,
    explanation:"الماء القديم الذي يبقى في مكان واحد دون أن يجري يصبح مكانًا مثاليًا للحشرة المسمّاة البعوض كي تضع بيضها. وإذا تركت دلاءً أو إطارات قديمة أو علبًا فارغة فيها ماء حول فِناء بيتك أو منزلك، يولد هناك مئات وآلاف من البعوض الجديد ويطير في كل مكان. وعندما يمتصّ البعوض دم إنسان، يحقن في جسمه جراثيم أمراض مخيفة جدًا ومميتة مثل الملاريا وحمّى الضنك. والتخلّص من برك الماء حول البيت خطة مهمة لحماية عائلتك من هذه الأمراض الرهيبة." },
  { id:10, topic:"النظافة", emoji:"✋",
    question:"عندما تطول الأظافر، ماذا يتجمّع داخلها؟",
    choices:["تصبح اليدان أقوى","يتجمّع وسخ أسود وجراثيم تحت الأظافر","يصبح الطعام ألذّ","لا يتغيّر شيء"],
    answerIndex:1,
    explanation:"عندما تطول الأظافر، يدخل الطين والوسخ الأسود متراكمًا في الفراغ الضيّق بين الظفر والجلد عندما تلعب في التراب أو تساعد أو تعمل. والوسخ الذي يدخل هذا الفراغ لا يزول بسهولة بغسل اليدين العادي، فيصبح مخبأً مثاليًا للجراثيم. ومع الأظافر الطويلة، عندما تأكل بيديك أو تلمس وجهك أو جرحًا، تدخل تلك الجراثيم المختبئة بسهولة إلى جسمك. وإبقاء الأظافر قصيرة دائمًا طريقة أساسية للوقاية من الأمراض." },
  { id:11, topic:"آداب السعال", emoji:"🤧",
    question:"ماذا تفعل عندما تسعل أو تعطس؟",
    choices:["تفعلها باتجاه وجه شخص","تغطّي فمك وأنفك بيدك أو كمّك","تصرخ بصوت عالٍ","لا تفعل شيئًا"],
    answerIndex:1,
    explanation:"عندما تكون مصابًا بالزكام أو بمرض في الرئة، فإن سعلة أو عطسة واحدة تقذف من فمك وأنفك رذاذًا دقيقًا من الماء لا يُرى، إلى مسافة عدة أمتار وبقوة. وقد تحتوي كل قطرة على عشرات الآلاف من جراثيم المرض. وإذا سعلت باتجاه وجه شخص، فأنت تنقل إليه المرض مباشرة، وإذا لم تغطِّ شيئًا، تنتشر الجراثيم في الهواء وقد يمرض كل من في الغرفة نفسها. وعندما تسعل، فإن تغطية فمك وأنفك جيدًا بكمّك أو يدك تمنعك من نقل المرض إلى عائلتك وأصدقائك الأعزّاء من حولك." },
  { id:12, topic:"النظافة", emoji:"🗑️",
    question:"ماذا يحدث إذا تركت القمامة ملقاة قرب البيت؟",
    choices:["يصبح البيت نظيفًا","تتجمّع الفئران والحشرات الضارة وينتشر المرض","تتحوّل القمامة إلى زهور","لا توجد مشكلة"],
    answerIndex:1,
    explanation:"إذا رميت بقايا الطعام والقمامة بجانب بيتك مباشرة، تجذب الرائحة كائنات كثيرة مثل الفئران والذباب والصراصير. وهذه الكائنات تمشي عادة في المجاري والأماكن القذرة، فتحمل في أجسامها الكثير من الجراثيم المسبّبة لأمراض مخيفة. وعندما تتكاثر حول القمامة، تدخل في النهاية إلى البيت وتلوّث الطعام وماء الشرب الموجود في الداخل. ويجب رمي القمامة في مكان محدّد بعيد بما يكفي عن البيت، أو دفنها عميقًا في حفرة في الأرض." },
  { id:13, topic:"أسنان سليمة", emoji:"🪥",
    question:"ما السبب الرئيسي لتنظيف الأسنان بالفرشاة؟",
    choices:["لطلاء الأسنان باللون الأبيض","لتقليل جراثيم التسوّس في الفم وحماية الأسنان","لتقوية الفكّ","لملء المعدة"],
    answerIndex:1,
    explanation:"بعد الأكل، تبقى دائمًا بقايا طعام صغيرة في فراغات الأسنان وعلى سطحها. والكائنات غير المرئية المسمّاة جراثيم التسوّس، التي تعيش في فمنا، تعشق هذه البقايا. وإذا تركتها هناك، تتغذّى عليها جراثيم التسوّس وتصنع حمضًا قويًا يذيب الأسنان. وبسبب هذا الحمض، تنفتح ثقوب شيئًا فشيئًا في الأسنان التي يُفترض أنها أصلب جزء في الجسم، وعندما يصل إلى العصب يسبّب ألمًا شديدًا حتى لا تستطيع النوم ليلًا. وتنظيف الأسنان بالفرشاة بعد الأكل عمل ضروري تمامًا لإزالة طعام الجراثيم وحماية أسنانك." },
  { id:14, topic:"الوقاية من الإصابات", emoji:"👟",
    question:"لماذا تلبس حذاءً عند المشي في الخارج؟",
    choices:["لتكبر قدماك","لمنع الديدان والجراثيم في التربة من الدخول عبر جلد قدميك","للتدرّب على الجري","كي لا تتّسخ ملابسك"],
    answerIndex:1,
    explanation:"عندما تمشي حافي القدمين على التراب والطين، يمكن لكائنات دقيقة جدًا مختبئة في الأرض لا تُرى (يرقات الطفيليات) وللجراثيم أن تخترق الجلد الطري في باطن قدميك وتدخل بنفسها إلى جسمك. والديدان التي تدخل تستقرّ في بطنك (الأمعاء) وتسرق الغذاء الذي تأكله، فتجعلك مصابًا بفقر دم شديد، وتوقف نموّك، وتسحب طاقتك. ولبس الحذاء يحميك أيضًا من إصابات خطيرة بسبب الدوس على زجاج مكسور أو حجارة حادّة أو أشواك. فالبس دائمًا حذاءً أو صندلًا عندما تخرج." },
  { id:15, topic:"النظافة", emoji:"👕",
    question:"ماذا يحدث إذا واصلت لبس ملابس متّسخة؟",
    choices:["تصبح الملابس أمتن","تحكّ بشرتك أو تمرض","يصبح جسمك أقوى","لا يتغيّر شيء"],
    answerIndex:1,
    explanation:"إذا واصلت لبس ملابس مبلّلة بالعرق أو ملطّخة بالطين أيامًا كثيرة، يتغذّى العفن والجراثيم على العرق ودهن الجلد الموجود في الملابس ويتكاثر بشكل هائل داخل أليافها. ولأن هذه الملابس المتّسخة تحتكّ بجلدك طوال الوقت، قد يتورّم الجلد ويحمرّ، أو يحكّ كثيرًا، أو يُصاب بمرض فيه تقرّحات يسيل منها صديد. ويمكن تخليص الملابس المتّسخة من الجراثيم بغسلها جيدًا بالماء والصابون وتجفيفها جيدًا في الشمس (الأشعة فوق البنفسجية). ولبس ملابس نظيفة دائمًا مهمّ لحماية حاجز جلدك." },
  { id:16, topic:"النظافة", emoji:"🚿",
    question:"ما فائدة غسل الجسم؟",
    choices:["تنظف البشرة وتقي من أمراض الجلد","تطول قامتك","يتساقط شعرك","تجوع"],
    answerIndex:0,
    explanation:"كل يوم يخرج من جلد الإنسان دهن غير مرئي (الزهم) وعرق، ويختلط بهما الغبار والتراب من الخارج، فيتّسخ الجسم كله. وإذا تركت هذا الوسخ أيامًا كثيرة، تتكاثر الجراثيم السيئة على سطح الجلد، وقد تُصاب بدمامل رهيبة أو بمرض مخيف يتقرّح فيه الجلد ويتعفّن. وبغسل جسمك كله بانتظام وبرفق، بالماء والصابون، وإزالة الدهن والوسخ القديم، يبقى جلدك سليمًا وقويًا، فيشكّل حاجزًا قويًا يمنع المرض من الدخول من الخارج." },
  { id:17, topic:"ماء آمن", emoji:"💧",
    question:"عندما لا يتوفّر إلا ماء موحل، كيف تشربه بأمان؟",
    choices:["تشربه كما هو","تصفّي الطين بقماش أو رمل، ثم تغليه على النار","تتركه في الشمس فقط ثم تشربه","تشرب قليلًا فقط"],
    answerIndex:1,
    explanation:"عندما يكون كل ما تستطيع الحصول عليه ماءً موحلًا، فإن شربه كما هو يُدخل إلى جسمك كمية هائلة من الجراثيم مع الطين ويسبّب مرضًا خطيرًا. ويتطلّب جعله آمنًا حكمتين. أولًا، مرّر الماء عبر قماش نظيف ناعم، أو إناء مملوء بالرمل والحصى الصغير، لتصفية الطين والقطع الكبيرة وجعل الماء صافيًا. لكن الصفاء وحده لا يكفي؛ فالجراثيم غير المرئية لا تزال حية. بعد ذلك، يجب أن تضعه على النار وتغليه بقوة حتى تتصاعد الفقاعات، كي تقضي الحرارة على الجراثيم ويصبح أخيرًا ماء شرب آمنًا. وبالحكمة، يمكنك صنع ماء ينقذ الحياة حتى من ماء موحل." },
  { id:18, topic:"الرُّضّع", emoji:"🍼",
    question:"ما أفضل غذاء للرضيع؟",
    choices:["حليب البقر (نيء)","حليب الأم (الرضاعة الطبيعية)","ماء النهر","ماء بالسكر"],
    answerIndex:1,
    explanation:"جسم الرضيع حديث الولادة ضعيف جدًا وليس لديه تقريبًا قوة لهزيمة جراثيم الأمراض. وحليب الأم (الرضاعة الطبيعية) لا يحتوي فقط على غذاء مثالي كي ينمو الرضيع، بل أيضًا على كميات كبيرة من مكوّن واقٍ خاص يسمّى المناعة، يحميه من الأمراض. كما أن حليب الأم يخرج مباشرة من الجسم، فلا يلمس أبدًا ماءً متّسخًا من الخارج ولا جراثيم الأوعية؛ فهو الأنظف والأأمن في العالم. أما الحليب النيء من حيوانات أخرى، أو ماء النهر، أو ماء السكر، فقد يدمّر معدة الرضيع وأمعاءه الرقيقة ويسلب حياته، فلا يجوز أبدًا أن تعطيه إيّاها." },
  { id:19, topic:"الوقاية من الأمراض", emoji:"😷",
    question:"ماذا تفعل قرب شخص يسعل بشدة؟",
    choices:["تبقى على بعد قليل وتدير وجهك عند المرور","تأخذ نفسًا عميقًا أمامه","تصافحه","تقف أمامه تمامًا"],
    answerIndex:0,
    explanation:"أمراض التنفّس الخطيرة مثل السلّ تطفو في الهواء وقتًا طويلًا، محمولة على الرذاذ الدقيق غير المرئي الذي يتطاير عندما يسعل المريض. وإذا أخذت نفسًا عميقًا قريبًا منه، أو بقيت قريبًا وقتًا طويلًا، تستنشق تلك الجراثيم إلى أعماق رئتيك وقد تُصاب بالمرض الخطير نفسه. وعندما يسعل أحد بشدة، فالأمر ليس قسوة ولا معاملة مختلفة؛ بل لحماية نفسك، ابقَ على بعد عدة أمتار، وعند المرور أدِر وجهك وأخرج نفَسك بهدوء؛ فهكذا يحمي كلٌّ منكما الآخر." },
  { id:20, topic:"الهواء النقي", emoji:"🪟",
    question:"كيف تحافظ على نظافة هواء الغرفة؟",
    choices:["تغلق كل الأبواب والنوافذ بإحكام","تفتح النوافذ والأبواب لتجديد الهواء","يصرخ الجميع بصوت عالٍ معًا","لا يتغيّر شيء"],
    answerIndex:1,
    explanation:"عندما يتجمّع كثير من الناس في غرفة صغيرة مغلقة، تتراكم جراثيم وفيروسات يحملها أحدهم في الهواء أكثر فأكثر، حتى يمتلئ هواء الغرفة بالجراثيم. وإذا بقيت وقتًا طويلًا في تلك الغرفة، يستنشق الجميع الهواء المتّسخ ويمرضون معًا (عدوى جماعية). وبفتح النوافذ والأبواب في مكانين أو أكثر لتبديل الهواء النقي من الخارج بالهواء المتّسخ في الغرفة (التهوية)، يمكنك أن تطرد الجراثيم من الهواء وتحمي صحة كل من في الغرفة." },
  { id:21, topic:"الرافعة", emoji:"🪨",
    question:"عندما تريد تحريك حجر ثقيل مدفون في الأرض باستخدام عصا طويلة، أين يجب أن تضغط بأقوى قدر لتحرّكه بأقل قوة؟",
    choices:["في المكان الملاصق تمامًا للحجر","في منتصف العصا","في أبعد طرف للعصا، بعيدًا عن الحجر","لا فرق أينما ضغطت"],
    answerIndex:2,
    explanation:"عندما تحرّك شيئًا ثقيلًا بعصا، توجد قاعدة تُسمى «مبدأ الرافعة»: كلما ابتعدت عن الحجر الصغير الذي يعمل سندًا (نقطة الارتكاز)، قلّت القوة التي تحتاجها للضغط. لو ضغطت قرب الحجر فلن تتزحزح العصا، أما لو أمسكت أبعد طرف للعصا وضغطت متّكئًا بثقل جسمك، فتستطيع رفع حجر ثقيل بقوة صغيرة بشكل مدهش. ومعرفة كيف تعمل الأداة هكذا تتيح لك مضاعفة قوتك أضعافًا وإنجاز الأعمال الثقيلة بسهولة." },
  { id:22, topic:"الرافعة", emoji:"⚖️",
    question:"عندما ترفع حملًا ثقيلًا بعصا طويلة، أين يجب أن تضع الحجر الصغير (نقطة الارتكاز) الذي يسند العصا لكي يرتفع بأسهل ما يكون؟",
    choices:["ملاصقًا تمامًا للحمل الثقيل","ملاصقًا تمامًا للمكان الذي تبذل فيه قوتك","في منتصف العصا تمامًا","الأفضل ألا تضع حجرًا إطلاقًا"],
    answerIndex:0,
    explanation:"عندما ترفع شيئًا ثقيلًا بعصا، يكون موضع الحجر الصغير السند (نقطة الارتكاز) مهمًّا جدًا. بوضع هذا السند ملاصقًا تمامًا للحمل الثقيل، تقصُر المسافة التي يتحرّكها الحمل، لكن القوة التي تحتاجها لرفعه تصير أصغر بكثير. وعلى العكس، لو كان حجر السند قريبًا منك، فمهما ضغطت لن تستطيع رفع الحمل. وعندما تريد تحريك شيء ثقيل، تذكّر حكمة وضع السند قريبًا من الشيء الذي تريد تحريكه." },
  { id:23, topic:"التدحرج", emoji:"🪵",
    question:"عندما تنقل صندوقًا خشبيًا ثقيلًا بجرّه على الأرض، كيف تستطيع تحريكه بأسهل ما يكون وبأقل قوة؟",
    choices:["تضع تحت الصندوق عدة جذوع مستديرة صلبة وتدحرجه","تشدّه بكل قوتك كما هو","تصبّ الماء فوق الصندوق","تضرب الصندوق بقوة على الأرض"],
    answerIndex:0,
    explanation:"عندما تجرّ شيئًا ثقيلًا مباشرة على الأرض، تعمل بقوة كابحة تُسمى الاحتكاك، تنشأ حيث يحتكّ الشيء بالأرض، فتحتاج إلى قوة هائلة لتحريكه. لكن لو وضعت تحت الصندوق جذوعًا مستديرة صلبة، تحوّلت الحركة من الجرّ إلى تدحرج الجذوع. والتدحرج قوته الكابحة أقل بعشرات المرات من الجرّ، فيستطيع شخص واحد أن ينقل حملًا ثقيلًا بسلاسة. وعندما يتقدّم الحمل، تأخذ الجذوع التي خرجت من الخلف وتضعها أمامه من جديد، حكمة استخدمها البشر منذ القدم." },
  { id:24, topic:"المنحدر", emoji:"🛝",
    question:"عندما تريد رفع حمل ثقيل إلى منصة عالية بارتفاع صدر شخص بالغ تقريبًا، أيّ طريقة نقل أقلّ إجهادًا لجسمك؟",
    choices:["تقف أمام المنصة وترفعه مستقيمًا إلى أعلى بكل قوتك","تسند لوحًا طويلًا مائلًا على المنصة لتصنع منحدرًا، وتدفعه إلى أعلى","ترمي الحمل نحو المنصة من بعيد","تنحت ارتفاع المنصة لتجعلها أوطأ"],
    answerIndex:1,
    explanation:"لو حاولت رفع حمل ثقيل مستقيمًا إلى أعلى، فإنك تواجه مباشرةً القوة التي تشدّ الأشياء نحو الأرض (الجاذبية)، فتضطر إلى حمل كل الثقل بعضلاتك وحدها، وهذا يؤذي ظهرك وذراعيك. هنا، لو أسندت لوحًا طويلًا مائلًا على المنصة لتصنع منحدرًا (مستوى مائلًا)، صار اللوح يحمل معظم وزن الحمل. وعلى المنحدر تطول المسافة التي تمشيها، لكن القوة اللازمة لدفع الحمل يمكن خفضها إلى أقل من النصف. وعند نقل الأشياء إلى مكان عالٍ، ابحث دائمًا عن طريقة لصنع منحدر." },
  { id:25, topic:"البَكَرة", emoji:"🪣",
    question:"عندما تسحب بحبل دلوًا ثقيلًا مملوءًا بالماء من بئر عميقة، ما الذي يصير أسهل لو ركّبت على العارضة فوق البئر عجلة مستديرة تدور (بَكَرة) ومرّرت الحبل عليها؟",
    choices:["يصير وزن الماء أخفّ إلى النصف","تزداد كمية الماء من تلقاء نفسها","تستطيع رفع الماء بمجرد شدّ الحبل إلى أسفل","لن ينقطع الحبل أبدًا"],
    answerIndex:2,
    explanation:"عندما تمرّر حبلًا على العجلة المستديرة فوق البئر (بَكَرة ثابتة)، فإن وزن الماء نفسه لا يخفّ في الحقيقة. لكن روعة هذه الأداة أنها تغيّر اتجاه بذلك قوتك. لو حاولت رفع الحبل مستقيمًا إلى أعلى، فعليك رفعه بقوة ذراعيك وظهرك وحدها؛ أما لو مرّرت الحبل على العجلة المستديرة وشددت إلى أسفل، فتستطيع أن تُلقي بكامل ثقل جسمك على الحبل. والقدرة على استخدام ثقل جسمك لسحب الماء الثقيل بسهولة وأمان هي حكمة هذه العجلة المستديرة." },
  { id:26, topic:"المحور والعجلة", emoji:"🔄",
    question:"عندما تريد لفّ برغي لا يدور أبدًا، أو مِرفاع بئر ثقيل، كيف تستطيع لفّه بأسهل ما يكون؟",
    choices:["تلفّه بقضيب قصير ورفيع","تجعل جزء المقبض كبيرًا وطويلًا وتلفّ ذلك","تلفّه بأطراف أصابعك فقط، بلا أداة","تضرب البرغي بقوة بمطرقة"],
    answerIndex:1,
    explanation:"عندما تريد لفّ محور في المركز، لو ركّبت على ذلك المحور مقبضًا مستديرًا كبيرًا أو يدًا طويلة، استطعت توليد قوة دوران كبيرة بجهد صغير. ويُسمى هذا مبدأ العجلة والمحور. لا تستطيع تحريك الجزء الرفيع بلفّه مباشرة بأصابعك، لكن عندما تلفّ المقبض الكبير الخارجي، تطول المسافة التي تقطعها يدك، بينما تصير القوة على المحور أقوى أضعافًا. الآلة التي تلفّ حبل البئر، ومقبض الباب في البيت، وبراغي الأدوات؛ كل شيء يدور حولك يستخدم هذه الحكمة." },
  { id:27, topic:"مركز الثقل", emoji:"🏺",
    question:"هناك أناس يمشون بمهارة وهم يحملون جرّة ماء ثقيلة أو حطبًا فوق رؤوسهم. لماذا يستطيعون المشي مسافات طويلة دون أن يؤذوا الرقبة أو الظهر؟",
    choices:["لأنهم يمشون وهم يثنون أجسامهم كثيرًا إلى الأمام أو الخلف","لأنهم يبقون ظهورهم مستقيمة تمامًا ويضعون مركز الحمل (مركز ثقله) فوق عظامهم مباشرة","لأنهم يهزّون الحمل بعنف فوق رؤوسهم طوال الوقت","لأن الجميع يولدون بعظام رقبة أسمك من غيرهم"],
    answerIndex:1,
    explanation:"عندما تحمل حملًا ثقيلًا بيديك، يقع العبء على جانب واحد من الجسم وتتعب عضلاتك بسرعة. لكن لو قوّمت ظهرك تمامًا ووضعت الحمل فوق رأسك مباشرة، فإن وزن مركز الحمل (مركز ثقله) ينزل مستقيمًا عبر عمود العظام، من الرأس إلى الرقبة ثم العمود الفقري، ويخرج إلى الأرض. ولأن العظام المتينة، لا العضلات، هي التي تحمل الوزن، تستطيع حمله بأمان مسافات طويلة دون هدر قوة عضلية، ما دمت تحافظ على توازنك. وإبقاء الأشياء قريبة من المحور المركزي لجسمك حكمة مهمة كي لا تؤذي نفسك." },
  { id:28, topic:"الضغط", emoji:"🦶",
    question:"عندما تمشي على طريق موحل يصير بعد المطر وحلًا عميقًا تغوص فيه القدمان، كيف تمشي أسهل دون أن تغوص؟",
    choices:["تمشي على رؤوس أصابع قدميك، تجعل باطن قدميك أصغر ما يمكن","تربط على باطن قدميك لوحًا خشبيًا مسطحًا وكبيرًا وتمشي","تكتفي بالصراخ بصوت عالٍ وتعبر راكضًا","تحمل أمتعة كثيرة لتزيد وزنك"],
    answerIndex:1,
    explanation:"الوزن الذي يضغط على الأرض يتركّز أكثر في نقطة واحدة ويغوص أعمق، كالإبرة، كلما صغرت المساحة التي تلامسه. ويُسمى هذا «الضغط». والوقوف على رؤوس الأصابع يصغّر المساحة، فتغوص أعمق. وعلى العكس، لو ربطت على باطن قدميك لوحًا خشبيًا مسطحًا وكبيرًا، توزّع وزنك على مساحة واسعة، فتضعف القوة الدافعة للأرض إلى أسفل وتستطيع المشي على الوحل دون أن تغوص. وجعل قاعدة المبنى الثقيل واسعة ومسطحة هو الحكمة نفسها لتوزيع الضغط." },
  { id:29, topic:"العربات", emoji:"🛒",
    question:"عندما تريد تحميل عربة بعجلتين بكثير من الأمتعة الثقيلة وجرّها، أين تضع الأشياء الثقيلة لتكون أخفّ وأسهل في الجرّ؟",
    choices:["ملاصقًا ليديك تمامًا، قرب المقبض","في أقصى مؤخرة العربة","فوق محور العجلتين مباشرة","لا فرق أينما حمّلت"],
    answerIndex:2,
    explanation:"عندما تجرّ عربة، يتغيّر الوزن على يديك تغيّرًا هائلًا حسب موضع وضعك للحمل. لو حمّلت الأمتعة الثقيلة قرب يديك، انتهى بك الأمر تركض وأنت ترفع وزن الحمل بذراعيك مباشرة، وتتعب بسرعة. ولو كانت بعيدة جدًا إلى الخلف، انقلبت العربة إلى الوراء، وهذا خطر. الجواب الصحيح هو فوق محور العجلتين مباشرة. لو وضعت الأشياء الثقيلة هنا، حملت العجلتان المتينتان والأرض كل الوزن، فلا يقع على يديك وزن يُذكر. ولأنك تحتاج فقط إلى قوة الجرّ إلى الأمام، تستطيع نقل حمل كبير بسهولة بالغة." },
  { id:30, topic:"النصل", emoji:"🔪",
    question:"عندما تشحذ حدّ ساطور تشقّ به الحطب، أو سكين مطبخ تقطع به الطعام، بفركه على حجر (حجر الشحذ)، لماذا يصير أقطع؟",
    choices:["لأن طرف الحدّ يصير أرقّ وأدقّ، فتتركّز القوة في نقطة واحدة","لأن الحدّ يسخن فيُذيب الطعام","لأن الحدّ يصير أثقل","لأن الحدّ يصير مستديرًا"],
    answerIndex:0,
    explanation:"كون الشيء يُقطع بالحدّ يحدث لأن القوة التي يبذلها الإنسان تتركّز على المكان البالغ الضيق في طرف الحدّ فتخترق الشيء. وعندما يَقدُم الحدّ ويستدير، تتوزّع القوة على مساحة واسعة، فمهما ضغطت لا يقطع. وشحذ الحدّ هو عمل نحت الطرف المستدير ليصير أدقّ وأرقّ ما يمكن. وما إن يصير الطرف دقيقًا، حتى تولّد القوة الصغيرة ضغطًا هائلًا في تلك النقطة، فتستطيع شقّ الحطب الصلب أو الطعام بلمسة خفيفة. والعناية بأدواتك أساس لتوفير قوتك." },
  { id:31, topic:"الاحتكاك", emoji:"👟",
    question:"عندما تمشي على منحدر أو على صخور مبتلّة، أيّهما أقلّ انزلاقًا وأكثر أمانًا: حذاء أملس زلِق، أم حذاء بنعل ذي أخاديد عميقة ذات أسنان؟",
    choices:["حذاء أملس مسطّح","حذاء بنعل ذي أخاديد عميقة ذات أسنان","لا فرق أيًّا لبست","الانزلاق أقلّ دون حذاء إطلاقًا"],
    answerIndex:1,
    explanation:"عندما يحتكّ نعل الحذاء بالأرض، تعمل هناك قوة كابحة تُسمى الاحتكاك تمنعك من الانزلاق. لو كان النعل أملس، فلا كابح يعمل بينه وبين الأرض، فتنزلق وتقع بسهولة، خاصة حيث يوجد ماء أو وحل. ولو كان للنعل أخاديد عميقة ذات أسنان، اشتبكت تلك الأخاديد بقوة في نتوءات الأرض وولّدت كبحًا قويًا. والانزلاق والوقوع قد يؤدّيان إلى إصابة خطيرة، لكن بمعرفة كيف يعمل الاحتكاك، باختيار حذاء ذي أخاديد على الأرض الزلِقة أو بوضع باطن قدمك كلّه بثبات على الأرض، تستطيع التصرّف بأمان." },
  { id:32, topic:"الطفو", emoji:"⛵",
    question:"الحصاة الصغيرة تغرق في الماء، ومع ذلك سفينة خشبية أثقل وأكبر منها بآلاف المرات تستطيع أن تطفو على الماء. لماذا؟",
    choices:["لأن السفينة على شكل وعاء تحتضن كثيرًا من الهواء والماء في داخلها","لأن السفينة تتلقّى رياحًا كثيرة","لأن في قاعها أحجارًا سحرية مدهونة","لأن السفينة مصنوعة من زيت أخفّ من الماء"],
    answerIndex:0,
    explanation:"على الجسم في الماء تعمل قوة عجيبة تُسمى «قوة الطفو»، تدفعه إلى أعلى بمقدار ما يزيحه من ماء. الحصاة مصمتة في داخلها وثقيلة، فالحصاة أثقل من الماء الذي تزيحه، فتغرق. أما السفينة الكبيرة فعلى شكل وعاء، وفي داخلها كثير من الهواء. وبالنظر إليها ككلّ، تصير خفيفة جدًا بالنسبة إلى حجمها، فتصير قوة الماء الدافعة من أسفل أقوى، وتستطيع حتى السفينة الكبيرة أن تطفو على الماء دون أن تنقلب." },
  { id:33, topic:"المثلثات", emoji:"🔺",
    question:"عندما تبني بيتًا أو جسرًا من الخشب أو الحديد، لماذا يصنع تركيب الهيكل على شكل مثلثات مبنى متينًا جدًا يصعب كسره؟",
    choices:["لأنه يحتاج موادّ أكثر من المربّع","لأن المثلث يتميّز بأن شكله لا يتشوّه أبدًا، حتى لو طُبّقت عليه قوة قوية من أعلى","لأن صنع المثلثات يجعل الريح تمرّ أسهل","لأنه شكل قديم يُستخدم تعويذة من الآلهة"],
    answerIndex:1,
    explanation:"المبنى المركّب من أعمدة على شكل مربّعات فقط ينهار بسهولة، إذ تنثني وصلاته متراخية، عندما تُطبّق قوة قوية أو هزّة زلزال من أعلى أو من الجانب. لكن لو أضفت قضيبًا مائلًا داخل ذلك المربّع لتصنع مثلثًا (هيكلًا جمالونيًا)، فمن أيّ اتجاه أتت القوة، تتجاذب القضبان وتتساند فلا يتشوّه الشكل إطلاقًا. ولو نظرت إلى الجسور الكبرى في العالم، أو إلى أسفل أسقف المباني، لوجدت هذه المثلثات مركّبة بدقة دائمًا. إنها حكمة بناء رائعة: حتى بموادّ قليلة، بمجرد التفكير في الشكل تستطيع صنع شيء أمتن أضعافًا." },
  { id:34, topic:"القصور الذاتي", emoji:"🐎",
    question:"عندما يكبح حصان أو عربة مسرعة فجأة ويتوقّف توقّفًا تامًّا، ماذا يحدث للأمتعة والناس المحمولين فوقها؟",
    choices:["ينقلبون إلى الخلف كما هم","يُقذَفون إلى الأمام بقوة","يقفزون مستقيمين إلى أعلى في مكانهم","لا يحدث شيء؛ يتوقّفون توقّفًا تامًّا أيضًا"],
    answerIndex:1,
    explanation:"في الكون قوة عجيبة تُسمى «القصور الذاتي»: الشيء المتحرّك يسعى إلى الاستمرار في الحركة بالسرعة نفسها. وحتى لو توقّف الحصان أو العربة فجأة، فإن الناس والأمتعة فوقها ما زالوا يسعون إلى الاستمرار في التقدّم. لذا، ما لم تثبّت قدميك بقوة أو تربط الحمل بحبل، تُقذَف إلى الأمام بقوة وتُصاب إصابة بالغة. وعند إيقاف شيء متحرّك، أو عند ركوبك مركبة سريعة، يجب أن تضع في ذهنك أن هذه القوة التي تسعى إلى قذف الأشياء إلى الأمام تعمل دائمًا، وأن تستعدّ من أجل سلامتك." },
  { id:35, topic:"المقص", emoji:"✂️",
    question:"عندما تريد قصّ غصن صلب أو قماش سميك بالمقصّ، عند أيّ موضع من الشفرة تَحصُره لتقصّ بأسهل ما يكون وبأقل قوة؟",
    choices:["عند أقصى طرف الشفرة","عند أصل الشفرة (الأقرب إلى البرغي أو المفصل)","عند منتصف الشفرة","القوة اللازمة واحدة أينما قصصت"],
    answerIndex:1,
    explanation:"المقصّ أيضًا أداة مفيدة جدًا تستخدم مبدأ الرافعة الذي تعلّمناه. البرغي الذي تتقاطع عنده الشفرتان وتُثبّتان يصير سندًا (نقطة ارتكاز). وكلما اقتربت من برغي السند هذا في القصّ، صارت القوة التي تنقلها يدك القابضة إلى الشفرة أقوى أضعافًا. لذا، مع الشيء الصلب الذي لا يُقصّ، محاولة قصّه بطرف المقصّ لا تؤذي إلا يدك، أما لو حصرته عميقًا عند أصل الشفرة وقبضت، فتستطيع قصّه بقوة صغيرة بشكل مدهش. اعرف خصائص أدواتك واستخدم الموضع الأكثر كفاءة." },
  { id:36, topic:"الجاذبية", emoji:"🍎",
    question:"لماذا، بين إسقاط حصاة صغيرة على القدم من ارتفاع الركبة، وإسقاطها من أعلى سطح البيت المرتفع، تُسبّب الساقطة من السطح إصابة أشدّ؟",
    choices:["لأن الحجر يصير أبرد في الأعلى على السطح","لأن الجاذبية، القوة التي تشدّ الأشياء نحو الأرض، تجعل الحجر أسرع فأسرع كلما طال السقوط، فتكون الصدمة عند الارتطام أقوى","لأن الحجر في مكان عالٍ يصير أكبر حجمًا","لأن الهواء يدفع الحجر إلى أسفل"],
    answerIndex:1,
    explanation:"كل شيء على الأرض تشدّه باستمرار قوة تُسمى «الجاذبية»، تجذبه نحو الأرض. والشيء في مكان عالٍ، كلما طال سقوطه، استمرّت الجاذبية في شدّه أكثر فيتسارع أسرع فأسرع. والجسم الذي تسارع يولّد قوة تدميرية هائلة (طاقة) لحظة ارتطامه بالأرض أو بجسمك. من ارتفاع الركبة لا يكون إلا مؤلمًا، أما الساقط من سطح عالٍ أو جُرف، ولو كان حجرًا صغيرًا أو أداة، فيصير سلاحًا قادرًا على إزهاق روح إنسان. وعند العمل قرب مكان عالٍ، يجب أن تتأكّد ألّا أحد في الأسفل وأن تحرص أشدّ الحرص ألّا تُسقط شيئًا." },
  { id:37, topic:"التوازن", emoji:"⚖️",
    question:"عندما تحمل على كتفك عصا طويلة (عصا حمل) معلّقًا في مقدّمها ومؤخّرها جرّتا ماء ثقيلتان، كيف تمشي بسهولة دون أن يؤلمك كتفك؟",
    choices:["تجعل حمل المقدّمة ثقيلًا جدًا وحمل المؤخّرة خفيفًا","تجعل حملَي المقدّمة والمؤخّرة متساويين تمامًا في الوزن، وتضع منتصف العصا تمامًا على كتفك","لا تضع العصا على كتفك؛ تحملها باليدين فقط","تُسقط الحملين على الأرض بالتناوب وأنت تركض"],
    answerIndex:1,
    explanation:"عندما تحمل أحمالًا معلّقة على جانبي عصا طويلة، لو كان وزنا المقدّمة والمؤخّرة غير متساويين، مالت العصا إلى جهة واحدة، فتضطر إلى مكافحة لتثبيتها بيديك. وهذا يُتعب بسرعة لا الكتف فحسب، بل الذراعين والظهر أيضًا. الجواب الصحيح هو جعل حملَي المقدّمة والمؤخّرة بالتوازن نفسه تمامًا. وهكذا يقع الوزن بالتساوي فوق كتفك مباشرة عبر العصا، وتستطيع حمل أحمال ثقيلة بمجرد المشي، دون استخدام عضلات زائدة لمكافحة الميل. ولو كان أحد الحملين أخفّ لا محالة، فاضبط التوازن بإزلاق حبل الجهة الخفيفة نحو طرف العصا." },
  { id:38, topic:"مقاومة الهواء", emoji:"🪂",
    question:"لديك ورقتان متساويتان في الحجم والوزن. واحدة تُترك ورقة مسطّحة، والأخرى تُكوّر باليد كرةً متماسكة. وعندما تُسقطهما معًا من مكان عالٍ، أيّهما تصل إلى الأرض أولًا؟",
    choices:["الورقة المسطّحة كما هي","الورقة المكوّرة كرة متماسكة","تصلان معًا في الوقت نفسه تمامًا","يتغيّر كل مرّة حسب الريح"],
    answerIndex:1,
    explanation:"حتى للأشياء المتساوية في الوزن، عند سقوطها في الهواء تعمل قوة كابحة تُسمى «مقاومة الهواء»، إذ يعترضها الهواء. الورقة المسطّحة مساحتها واسعة، فتلتقط كثيرًا من الهواء تحتها ولا تسقط إلا ببطء، كالمظلّة. أما الورقة المكوّرة كرةً صغيرة فتلامس الهواء بمساحة ضيّقة جدًا، فلا تتلقّى كبحًا يُذكر وتسقط سريعًا، تشدّها الجاذبية مستقيمةً إلى أسفل. ودوران الطاحونة بالريح، أو كاد المظلّة أن تطير في يوم عاصف، له علاقة أيضًا بقوة كبح الهواء هذه." },
  { id:39, topic:"المرونة", emoji:"🏹",
    question:"عندما تثني بكل قوتك خيزرانًا صلبًا متينًا، أو غصن شجرة مرنًا، ثم تُفلته فجأة، يرتدّ بقوة إلى شكله الأصلي. في أيّ شيء تستطيع استخدام هذه الخاصية (المرونة) لتصنع أداة نافعة في الحياة اليومية؟",
    choices:["ثلّاجة كي لا يفسد الطعام","«قوس وسهم» لرمي سهم نحو فريسة بعيدة، أو «فخّ» يقذف الأشياء الثقيلة","مرشّح لتنقية الماء","أداة لصبغ الثياب بالأبيض"],
    answerIndex:1,
    explanation:"المطّاط والنوابض، وكذلك الخيزران وأغصان الشجر، لها خاصية عجيبة تُسمى «المرونة»: عند بذل قوة ينثني شكلها، وعند الإفلات تسعى إلى العودة إلى شكلها الأصلي بسرعة عالية. وما دمت تمسكها مثنيّة بيدك، تُخزَّن القوة التي يبذلها الإنسان لحظةً داخل تلك الأداة على شكل طاقة. ولحظة الإفلات، تُطلَق تلك القوة المخزّنة دفعة واحدة، فتستطيع رمي سهم أبعد أضعافًا، أو تحريك فخّ، مما لو رميت بذراعك وحدها. وباستغلال هذه القوة التي تملكها نباتات الطبيعة، صنع البشر منذ القدم أدوات للصيد والحياة اليومية." },
  { id:40, topic:"التزييت", emoji:"🛢️",
    question:"عجلات العربة، أو مفصل الباب، صارت تُصدر صريرًا مزعجًا وتثقُل كلما حرّكتها. لو قطّرت هنا بضع قطرات من الزيت، لماذا تعود تتحرّك بخفّة؟",
    choices:["لأن الزيت يُذيب الحديد فيخفّفه","لأن الزيت يتصلّب ويصير غراءً","لأن الزيت يتسلّل إلى الفجوة بين المعدن والمعدن ويقلّل بشدّة قوة كبح الاحتكاك","لأن رائحة الزيت تطرد الحشرات"],
    answerIndex:2,
    explanation:"عندما تتحرّك آلة أو أداة، توجد مواضع يحتكّ فيها المعدن بالمعدن مباشرةً وبقوة. وتعمل هناك قوة كابحة قوية جدًا تُسمى الاحتكاك، وإن تُركت تآكلت وتلفت، أو لزم لتحريكها قوة هائلة. وعندما تضع الزيت، يتكوّن غشاء رقيق من الزيت في فجوة المعدن الضيّقة ويمنعها من الاحتكاك المباشر. ولأن قوة الكبح تزول دفعة واحدة، تتحرّك الأداة بسلاسة مدهشة وبقوة قليلة. ومجرّد وضع قليل من زيت الطعام أو الزيت النباتي على أداة، يجعلها تدوم أطول ويقلّل كثيرًا استنزاف قوى الإنسان." },
  { id:41, topic:"الصواعق", emoji:"⚡",
    question:"عندما يقصف الرعد وأنت في الخارج، أين الأأمن أن تحتمي؟",
    choices:["تحت شجرة عالية مباشرة","في وسط ساحة مكشوفة واسعة","داخل مبنى متين، أو سيارة محاطة بالمعدن","واقفًا تحمل مظلة كبيرة"],
    answerIndex:2,
    explanation:"للصاعقة ميل قوي إلى الضرب في الأشياء العالية. لذلك إن وقفت وحدك في ساحة مكشوفة، تصير أعلى جسم مدبّب حولك، ويصبح خطر الضربة المباشرة عاليًا جدًا. كما أن الوقوف تحت شجرة عالية مباشرة خطر: فالصاعقة التي تضرب الشجرة قد تقفز إلى جسدك، ظاهرة تُسمى «الضربة الجانبية»، وتسبب إصابة قاتلة. أأمن الأماكن داخل مبنى متين من الخرسانة، أو داخل سيارة محاطة بألواح معدنية. وحتى لو ضربت الصاعقة السيارة، يمر التيار عبر المعدن الخارجي وينزل إلى الأرض، فيكون من في الداخل في أمان تام." },
  { id:42, topic:"الفيضانات", emoji:"🌊",
    question:"حين يحوّل المطر الغزير الطريق إلى نهر ولا خيار أمامك إلا السير في الماء للإخلاء، فما الأأمن أن تلبسه في قدميك؟",
    choices:["حافي القدمين","صنادل","حذاء مربوط بإحكام بأربطة","حذاء مطاطي طويل"],
    answerIndex:2,
    explanation:"يخفي قاع الطريق الغارق مخاطر كثيرة غير مرئية: زجاج مكسور، علب حادة، فتحات مجارٍ مفتوحة. حافيًا أو بصنادل تجرح قدميك بسهولة ولا تعود تستطيع الحركة. يبدو الحذاء المطاطي جيدًا، لكن ما إن يدخله الماء من الأعلى حتى يصير ثقيلًا كوسائد ماء، ولا ترتفع القدمان البتة، فيمنعك من المشي أو يغرقك. الأأمن حذاء لا يخلع وبنعل صلب: حذاء رياضي مربوط بإحكام بأربطة. لا يثقل حتى لو دخله الماء، ويحمي قدميك ويتيح لك السير بثبات." },
  { id:43, topic:"الإخلاء", emoji:"⛰️",
    question:"جاء فيضان من مطر غزير أو تسونامي، والماء يقترب من قدميك. إلى أي اتجاه يصحّ الفرار؟",
    choices:["إلى المصبّ حيث يجري الماء بسرعة (مكان منخفض)","إلى تلّ أو جبل عالٍ قريب، أو طابق علوي في مبنى متين (مكان مرتفع)","إلى بيت قريب يسكن بعيدًا","إلى قبو بيتك (أخفض من الأرض)"],
    answerIndex:1,
    explanation:"في الفيضان أو التسونامي، يتجمع الماء بقوة هائلة، بدءًا من أخفض الأماكن. إن اختبأت في قبو أخفض من الأرض، يندفع الماء من المدخل دفعة واحدة، فلا تستطيع الخروج وتغرق. كما أن محاولة الفرار بعيدًا بالتجوال قد تجعلك تصطدم بأشجار أو سيارات منجرفة، أو يجرف التيار العنيف قدميك فتُحمَل بعيدًا. حين يقترب الماء، القاعدة ليست الذهاب بعيدًا، بل التوجّه إلى «أقرب مكان مرتفع من حيث أنت الآن». الصعود إلى تلّ أو جبل قريب، أو إلى الطابق الثاني أو الثالث من مبنى خرساني متين، وانتظار انحسار الماء، هو الخيار الذي يحمي حياتك." },
  { id:44, topic:"ضربة الشمس", emoji:"🥵",
    question:"في يوم شديد الحرّ والشمس قوية جدًا، ما الأهم للوقاية من المرض الذي يسخن فيه الجسم فتسقط مغشيًّا عليك (ضربة الشمس)؟",
    choices:["الصبر دون شرب الماء","طلاء كل الجسم بطين بارد","الراحة في الظل وشرب ماء آمن قليلًا قليلًا، مرات كثيرة","الركض كثيرًا لتتعرّق"],
    answerIndex:2,
    explanation:"إن بقيت طويلًا في مكان شديد الحرّ، يخرج الماء والملح من جسدك عرقًا، ولا يعود الجسم قادرًا على خفض حرارته بنفسه. هذه هي الحالة المرعبة المسماة ضربة الشمس. للوقاية منها، المهم أن تجد «ظلًّا باردًا» لا تصيبك فيه الشمس مباشرة، وتريح جسدك. وعليك شرب ماء آمن مغليّ ثم مبرّد، قليلًا قليلًا ومرات كثيرة، حتى قبل أن تشعر بالعطش. فبدل شرب الكثير دفعة واحدة، يجعل الشرب برشفات صغيرة متكررة الجسم يمتصّ الماء جيدًا، فتقضي اليوم بنشاط وأمان حتى تحت الشمس القوية." },
  { id:45, topic:"الزلازل", emoji:"🪑",
    question:"عندما يحدث زلزال وتبدأ الأرض وبيتك بالاهتزاز بعنف، ما أول ما تفعله داخل الغرفة؟",
    choices:["الاندفاع إلى الخارج بذعر","الاختباء تحت مكتب متين وحماية رأسك وجسدك","إغلاق النوافذ بإحكام والنظر إلى الخارج","حشر أشياء كثيرة في حقيبة"],
    answerIndex:1,
    explanation:"عند حدوث زلزال، الأخطر هو «سقوط الأشياء من الأعلى» و«انقلاب الأثاث». إن اندفعت إلى الخارج بذعر، قد يسقط من أعالي المباني زجاج مكسور وقرميد فيصيب رأسك، وهو خطر عالٍ جدًا للإصابة الخطيرة. ما إن تشعر بالاهتزاز، ادخل في مكانك تحت «مكتب أو سرير متين»، وأمسك بأرجل المكتب بإحكام واحمِ رأسك وجسدك. وإن لم يكن هناك مكان للاختباء، فغطِّ رأسك بإحكام بوسادة أو حقيبة أو ذراعيك، وتصاغر في وسط الغرفة حيث لا يسقط عليك الأثاث، وانتظر بهدوء حتى يتوقف الاهتزاز تمامًا، فهذا الأأمن." },
  { id:46, topic:"الصواعق", emoji:"⚡",
    question:"حين يقصف الرعد قريبًا جدًا، ما أخطر تصرّف في الخارج؟",
    choices:["حمل لعبة بلاستيكية","حمل قضيب معدني طويل أو صنّارة صيد مرفوعة عاليًا نحو السماء","لبس ثياب من قماش","لبس حذاء من خشب"],
    answerIndex:1,
    explanation:"للصاعقة ميل مرعب إلى الضرب المركّز في الأشياء «العالية وذات الطرف المدبّب». لذلك إن كنت في الخارج تحمل قضيبًا معدنيًا طويلًا أو صنّارة أو مظلة طويلة مرفوعة عاليًا نحو السماء، تصير كهوائي يستدعي الصاعقة، فتضربك مباشرة. حين تسمع قصف الرعد، أضجِع فورًا أي قضيب طويل تحمله أفقيًا على الأرض، واخفض وضعيتك قدر الإمكان، واجلس القرفصاء وأنزل رأسك. ثم أخلِ فورًا إلى داخل مبنى آمن." },
  { id:47, topic:"الانهيارات الأرضية", emoji:"⚠️",
    question:"حين يهطل مطر غزير بلا توقّف قرب جبل، ما العلامة الخطرة على أن الجبل قد ينهار (انهيار أرضي)؟",
    choices:["ماء النهر يصير فجأة أسود عكِرًا، وتنجرف قطع خشب كثيرة","تتساقط حصى صغيرة من الجبل قليلًا قليلًا","يأتي من أعماق الأرض صوت غريب كهدير الأرض","كل هذه علامات خطرة"],
    answerIndex:3,
    explanation:"حين ينهمر المطر الغزير على جبل، تمتصّ التربة كمية هائلة من الماء، وفي لحظة ما ينهار المنحدر أو الجبل كله دفعة واحدة، كارثة كبرى تُسمى «الانهيار الأرضي» أو «التدفق الطيني الصخري». قبل وقوعها مباشرة، تعطي الطبيعة دائمًا عدة إشارات تحذير. تعكّر ماء النهر فجأة وازدياد الأخشاب المنجرفة دليل على أن التربة في الأعلى بدأت تنهار. كما أن تساقط الحصى من الجبل، أو سماع صوت مخيف من الأرض، إشارة إلى أن الجبل كله يوشك أن يتحرك. إن وجدت أو شعرت بإحدى هذه الإشارات ولو واحدة، فعليك مغادرة المكان قبل ثانية والفرار إلى مكان مرتفع متين." },
  { id:48, topic:"الفيضانات", emoji:"🦯",
    question:"حين تضطر إلى السير في ماء فيضان، في طريق يجعل الطينُ الأرضَ غير مرئية تمامًا، كيف تسير لتكون آمنًا؟",
    choices:["الركض بأقصى سرعة للنجاة بسرعة","استخدام قضيب طويل لنقر الأرض والتأكد من سلامتها، خطوة بخطوة","إغماض العينين والسير قدُمًا","خلع كل الملابس والتقدّم سباحة"],
    answerIndex:1,
    explanation:"بعد الفيضان، يكون ماء الطريق بنيًّا عكِرًا مختلطًا بالطين والقمامة، فلا ترى البتة كيف هي الأرض تحت قدميك. في الواقع، قد يكون غطاء بالوعة قد انخلع تاركًا حفرة عميقة، أو تكون الأرض قد انجرفت إلى خندق عميق. إن ركضت أو مشيت دون أن تنتبه، قد تقع في حفرة عميقة في لحظة وتغرق. حين تسير في الماء، احمل دائمًا «قضيبًا طويلًا متينًا» كالعصا، وقبل أن تخطو الخطوة التالية، انقر الأرض بالقضيب لتتأكد «هل هناك حفرة»، متقدّمًا ببطء وحذر، فهذه طريقة المشي التي تحمي حياتك." },
  { id:49, topic:"الأعاصير القمعية", emoji:"🌪️",
    question:"حين يقترب إعصار قمعي (ريح عنيفة تدور بسرعة هائلة)، أين الأأمن أن تختبئ داخل البيت؟",
    choices:["بجانب نافذة ذات إطلالة جيدة على الخارج مباشرة","على السطح حيث الريح لطيفة","غرفة متينة بلا نوافذ، أو حمّام أو خزانة في وسط البيت","مستلقيًا على سرير كبير"],
    answerIndex:2,
    explanation:"الإعصار القمعي أعنف هبّة على الأرض، قوي بما يكفي لنزع سقف بيت أو رفع أشجار كبيرة وسيارات في الهواء. حين يقترب، الأكثر رعبًا هو «اختراق جسم طائر لزجاج النافذة وتطاير شظايا الزجاج في كل الغرفة بسرعة هائلة». لذا فالوجود قرب نافذة يعني إصابة خطيرة. أأمن مكان حيث الجدران أسمك وحيث لا توجد نوافذ البتة: «حمّام في وسط البيت، أو غرفة متينة، أو خزانة». احبس نفسك هناك، وغطِّ رأسك بوسادة أو لحاف، وتكوّر، وانتظر بهدوء مرور العاصفة، فهذه طريقة الاختباء الصحيحة." },
  { id:50, topic:"الحرائق", emoji:"🔥",
    question:"حين يندلع حريق ويتجمّع دخان كثير في الغرفة، كيف تهرب إلى الخارج؟",
    choices:["الوقوف منتصبًا والركض بأقصى سرعة","اتخاذ وضعية منخفضة بالزحف على الأرض، وتغطية الفم بقماش، والهرب","إغلاق كل النوافذ لحبس الدخان","التغطّي بلحاف كبير والنوم في السرير"],
    answerIndex:1,
    explanation:"يحتوي دخان الحريق على كثير من «السمّ الضار (كأول أكسيد الكربون)» الذي يُغمي على الإنسان لحظة استنشاقه. ولأن الدخان حارّ، يتجمّع في الغرفة أولًا «من السقف (الجزء العالي)»، ويبقى الهواء النظيف نسبيًا أخيرًا قرب الأرض. لذا إن وقفت منتصبًا، تستنشق أكثف الدخان السامّ مباشرة فلا تعود تستطيع الحركة. عند الهرب، حافظ على «وضعية منخفضة» وصدرك قرب الأرض، واضغط بإحكام قماشًا أو ثوبًا مبللًا على فمك وأنفك، وتنفّس الهواء قرب الأرض، واخرج سريعًا، فهذه طريقة الهرب الصحيحة." },
  { id:51, topic:"تسونامي", emoji:"🌊",
    question:"حين تكون قرب البحر وتشعر بزلزال عنيف، ما أهمّ ما يجب أن تفعله فورًا؟",
    choices:["الذهاب لرؤية إن كان في البحر سمك","العودة إلى البيت لجمع كل أغراضك","الابتعاد عن الشاطئ والصعود سريعًا إلى جبل عالٍ أو مرتفع متين","الجلوس بلا حراك على الشاطئ الرملي"],
    answerIndex:2,
    explanation:"حين يحدث زلزال كبير تحت البحر، تتحرك أرض القاع بشدة، فيندفع كل الماء المحيط كموجة عملاقة كالجدار، كارثة كبرى تُسمى «تسونامي». بخلاف الأمواج العادية، للتسونامي ثقل وقوة تدمير هائلان، قادران على جرف المباني والبيوت في لحظة. كما أن المدّ قد ينحسر فجأة قبل وصول التسونامي ويكشف الرمل، لكن إن ذهبت لرؤيته تسليةً، تبتلعك الموجة الكبرى في اللحظة التالية. إن شعرت بالاهتزاز قرب البحر، لا تحمل شيئًا، وابتعد عن البحر قبل ثانية، وافرّ إلى «تلّ أو جبل عالٍ، أو طابق علوي في مبنى متين». فبعد أن ترى الموجة، يكون الفرار قد فات." },
  { id:52, topic:"البرد", emoji:"🧥",
    question:"حين قد تضلّ الطريق في مكان شديد البرودة شتاءً، ما أفضل تصرّف للحفاظ على حرارة الجسم والبقاء على قيد الحياة؟",
    choices:["شرب كثير من الماء البارد","البقاء بثياب مبلّلة كما هي","الاختباء حيث لا تصيبك الريح، ولبس طبقات كثيرة من الثياب أو القماش","الاستلقاء للنوم مباشرة على الثلج"],
    answerIndex:2,
    explanation:"جسم الإنسان، إن هبطت حرارته كثيرًا، لا يعود قادرًا على الحركة ويفقد حياته (انخفاض حرارة الجسم). وبخاصة «الريح» و«الثياب المبلّلة» عدوّان خطران يسلبان حرارة الجسم في لحظة. لحماية نفسك في مكان بارد، الأولوية القصوى الاختباء حيث «لا تصيبك الريح البتة»، كخلف صخرة كبيرة أو داخل مبنى. ثم، إن كانت الثياب مبلّلة فبدّلها حتمًا بجافّة، والبس «طبقات كثيرة» مما لديك من ثياب وقماش وورق. تكديس القماش يخلق بين الطبقات طبقة هواء دافئ، جدارًا سحريًّا لا يدع حرارة جسدك تهرب. والنوم مباشرة على الثلج يسلب الحرارة، فبسط عشب أو كرتون على الأرض للجلوس عليه حكمة مهمة أيضًا." },
  { id:53, topic:"البراكين", emoji:"🌋",
    question:"حين يثور فجأة بركان قريب (جبل يقذف نارًا وطينًا حارّين)، كيف تحمي نفسك من الرماد والحجارة المتطايرة من السماء؟",
    choices:["النظر إلى السماء ومراقبة ما يسقط بانتباه","الدخول إلى مبنى متين (كبيت من خرسانة) وتغطية الفم والأنف بقماش","القفز في نهر قريب والسباحة","الركض بأقصى سرعة نحو الجبل"],
    answerIndex:1,
    explanation:"حين يثور بركان، تسقط من القمة من السماء «حِمَم» ثقيلة متوهّجة بالأحمر وحجارة كبيرة بسرعة مرعبة. وإن أصابت رأسك تهدّد الحياة، فعليك الاختباء فورًا داخل مبنى متين «من خرسانة أو ما شابه». كما أن «الرماد البركاني» الذي يقذفه البركان ليس رملًا عاديًا، بل كأشواك زجاج مطحون ناعم. استنشاقه يجرح الرئتين فلا تستطيع التنفّس، ودخوله العينين يسبب ألمًا شديدًا فلا تستطيع فتحهما. وبعد الاختباء في المبنى، أغلق النوافذ بإحكام، وغطِّ فمك وأنفك بإحكام بكمامة أو قماش مبلّل بالماء، واحمِ نفسك من استنشاق الرماد القذر أبدًا." },
  { id:54, topic:"الضباب", emoji:"🌫️",
    question:"حين يصير الضباب (ضبابة بيضاء تنتشر في الهواء) كثيفًا جدًا ولا ترى أمامك البتة، ما الأخطر عند المشي؟",
    choices:["التوقّف في مكانك","عدم سماع الأصوات من حولك بعد الآن","عدم رؤية موضعك أو الأماكن الخطرة كالمنحدرات، فتضلّ الطريق أو تسقط","ابتلال ثيابك قليلًا"],
    answerIndex:2,
    explanation:"حين يتكوّن ضباب كثيف، يصير حتى المنظر على بُعد أمتار قليلة أبيض ناصعًا ولا ترى شيئًا. إن أرغمت نفسك على متابعة السير هكذا، يُشلّ تمامًا حسّك بالاتجاه، أي إلى أين تسير، وقد يؤدي ذلك إلى حوادث كبيرة: التيه في غابة عميقة خطرة، أو عدم ملاحظة منحدر أو نهر عميق أمامك مباشرة فتهوي رأسًا حتى الموت. حين لا ترى أمامك، يجب ألّا تتقدّم بالقوة أبدًا. أأمن دفاع هو «التوقّف في مكانك» في موضع ثابت القدم، كوسط طريق واسع آمن، والانتظار بهدوء حتى ينقشع الضباب وترى ما حولك جيدًا من جديد." },
  { id:55, topic:"انهيار المنحدر", emoji:"🪨",
    question:"حين تكون قرب جدار ترابي عالٍ (منحدر) بعد هطول مطر غزير، مِمَّ يجب أن تحذر حتمًا؟",
    choices:["قد يتسرّب ماء المطر إلى المنحدر فينهار فجأة (انهيار المنحدر)، فابتعد فورًا","الصعود إلى أعلى المنحدر واللعب بمرح","نصب خيمة تحت المنحدر مباشرة والنوم","سكب كثير من الماء على جدار المنحدر"],
    answerIndex:0,
    explanation:"المنحدر أو السفح الترابي القديم، بعد مطر غزير، تكون في تربته كمية هائلة من الماء متجمّعة إلى الحدّ الأقصى، وهو في حالة هشّة جدًا، طريّة كالإسفنج. وحتى بعد توقّف المطر، بعد ساعات إلى أيام، يحدث كثيرًا «انهيار منحدر» ينهار فيه الجدار كله دفعة واحدة كأنه ينفجر، بلا أي صوت. إن لعبت أو نمت تحت المنحدر، تُدفن تحت أطنان من التراب الثقيل في لحظة ولا يمكن إنقاذك. أثناء المطر الغزير، وفي الأيام التي تلي توقّفه، التزم دائمًا بالقاعدة: «لا تقترب أبدًا من جدار ترابي عالٍ أو منحدر، ابتعد فورًا»." },
  { id:56, topic:"الإخلاء", emoji:"🏃",
    question:"حين يرتفع ماء النهر قرب بيتك أكثر فأكثر بسبب المطر الغزير ويوشك أن يفيض، متى يجب أن تبدأ الإخلاء؟",
    choices:["بعد أن يدخل الماء إلى داخل البيت","مبكرًا، ما دام الخارج مضيئًا ولم يتجمّع ماء على الطريق، ما دام آمنًا","الانتظار بهدوء حتى يفيض ماء النهر تمامًا","التفكير في الأمر بعد أن تدخل الفراش للنوم"],
    answerIndex:1,
    explanation:"محاولة الإخلاء بعد أن يفيض النهر ويبدأ الماء بالتجمّع على الطريق هي أخطر قرار وأكثره تأخّرًا. حين يتجمّع الماء إلى ارتفاع الركبة على الطريق، يُجرَف حتى الرجل البالغ بقوة الماء الشديدة ولا يستطيع المشي البتة. كما أنه حين يحلّ الظلام ليلًا، لا تعود تميّز أين الطريق وأين النهر، فتقع في النهر وتُجرَف في أثناء الإخلاء. أصحّ توقيت لبدء الإخلاء هو ما دام الخارج «مضيئًا ولم يتجمّع ماء عند قدميك، ما دام آمنًا». ما إن تشعر بخطر ولو قليل من النهر المرتفع، قلّل أغراضك إلى الحدّ الأدنى وانطلق مبكرًا نحو ملجأ مرتفع آمن، فهذه الحكمة التي تحمي حياتك بثبات." },
  { id:57, topic:"الصعق الكهربائي", emoji:"🔌",
    question:"بعد زلزال أو مطر غزير، تجد في البيت سلكًا كهربائيًا ممزّقًا يطلق شررًا. لماذا يجب ألّا تلمسه أبدًا؟",
    choices:["لأن يديك ستتّسخان بطين أسود","لأن الكهرباء القوية التي تجري في السلك تسري إلى جسدك وتسبب إصابة خطيرة، كتوقّف القلب (صعق كهربائي)","لأن السلك بارد كالثلج","لأن الغرفة ستصير مظلمة تمامًا"],
    answerIndex:1,
    explanation:"من سلك ممزّق، أو من جهاز كهربائي مبلّل بالماء، قد تتسرّب كهرباء قوية جدًا غير مرئية للعين البشرية. إن لمسته بيدك دون أن تدري، تخترق كهرباء السلك جسدك في لحظة وتنزل إلى الأرض. يُسمّى هذا «الصعق الكهربائي». تلقّي كهرباء قوية لا يحرق جسدك فحسب، بل قد يوقف قلبك فجأة، حادث قاتل في لحظة. وبخاصة حين يكون جسدك أو يداك مبلّلة بالماء، تسري الكهرباء إلى جسدك أسهل بأضعاف، وهو أخطر بعد. إن وجدت سلكًا يطلق شررًا أو سلكًا مقطوعًا، فلا تقترب أبدًا، ولا تلمس، وأبلغ شخصًا بالغًا." },
  { id:58, topic:"الأعاصير", emoji:"🌀",
    question:"حين تهبّ ريح قوية عاتية (إعصار أو إعصار حلزوني)، لماذا الخروج إلى الخارج خطر إلى حدّ يهدّد الحياة؟",
    choices:["لأن هواء الخارج ليس لذيذًا جدًا","لأن لافتات المحلات وقرميد الأسقف وأغصان الأشجار الكبيرة تتطاير وتصيب رأسك","لأن ثيابك المفضّلة تتّسخ بالطين","لأن تلقّي ريح قوية على كل الجسم يسبب السمنة"],
    answerIndex:1,
    explanation:"في عاصفة عاتية كإعصار أو إعصار حلزوني، تصير قوة الريح أبعد بكثير مما يتخيله البشر. أن تُحمَل بالريح نفسها خطر، لكن الأكثر رعبًا هو «أن يصير كل شيء في المدينة سلاحًا ويتطاير نحوك». لافتات المحلات الثقيلة، وقرميد الأسقف الصلب، وأغصان الأشجار المكسورة وغيرها تأتي طائرة من الجانب بسرعة كسكين حادّ أو رصاصة. وإن أصاب جسدَك واحدٌ منها فقط، فهي إصابة قاتلة. ما دمت تسمع صوت الريح القوية، مهما كان لديك من شأن، «يجب ألّا تخرج إلى الخارج أبدًا». البقاء في بيت آمن بعيدًا عن النوافذ، والانتظار بهدوء حتى تمرّ العاصفة تمامًا، هو التصرّف الصحيح." },
  { id:59, topic:"العواصف الرملية", emoji:"🏜️",
    question:"حين تحدث عاصفة رملية (رمل وغبار يثيرهما ريح قوية)، ماذا يجب أن تفعل لحماية عينيك ورئتيك؟",
    choices:["فتح العينين والفم على اتساعهما وتلقّي الريح","تغطية الوجه والفم والأنف بإحكام بوشاح أو قماش، والاختباء داخل مبنى متين","الخروج والتسابق ركضًا مع الأصدقاء","النظر إلى السماء لرؤية إلى أين يطير الرمل"],
    answerIndex:1,
    explanation:"العاصفة الرملية التي تحدث قرب صحراء أو في منطقة جافة عاصفة كبرى تثير بريح قوية مئات الملايين من حبيبات الرمل الدقيقة والغبار القذر. إن استنشقت هذا الرمل والغبار كما هما، يتراكم الرمل في عمق رئتيك فتسعل بعنف، مرض خطير لا تستطيع فيه التنفّس. كما قد تتأذّى العينان بالرمل فلا ترى. حين تقترب عاصفة رملية، أخلِ فورًا إلى داخل مبنى متين وأغلق النوافذ والأبواب دون فجوات. ثم كدّس عدة مرات الوشاح أو قماش الثياب الذي لديك و«غطِّ كل وجهك، وبخاصة الفم والأنف، بإحكام» لتصنع كمامة تمنع دخول الرمل. وحتى تمرّ العاصفة، احمِ نفسك بأن تتنفّس بهدوء الهواء المارّ عبر القماش فقط." },
  { id:60, topic:"الفيضانات", emoji:"🌊",
    question:"أثناء فيضان يندفع فيه الماء الموحل إلى البيت، لماذا الوجود في القبو (غرفة أخفض من الأرض) ممنوع منعًا باتًا؟",
    choices:["لأن القبو أبرد وأكثر راحة من بقية الغرف","لأن الماء الموحل من الطريق في الأعلى يندفع دفعة واحدة كشلّال، فيُسدّ المخرج وتغرق في لحظة","لأن القبو يصير مظلمًا حين ينقطع الكهرباء","لأنه أحيانًا تسكن فئران صغيرة في القبو"],
    answerIndex:1,
    explanation:"القبو أو الغرفة شبه الأرضية الأخفض من الأرض يتحوّل إلى «أكثر مكان مميت وأخطره في العالم» حين يحدث فيضان. الماء الموحل الذي فاض على الطريق في الأعلى يندفع دفعة واحدة عبر درج القبو ونوافذه بقوة وثقل شلّال هائلين. قوة الماء المنحدر على الدرج عنيفة، وحتى قوة شخص بالغ لا تستطيع مقاومتها للصعود. وعلاوة على ذلك، يضغط ثقل الماء على باب القبو من الخارج، فيصير من المستحيل تمامًا فتحه من الداخل. تمتلئ الغرفة بالماء في لحظة، ويُفقَد طريق النجاة تمامًا، فتغرق. حين يشتدّ المطر، القاعدة الحديدية المطلقة: «لا تقترب من القبو أبدًا، اصعد إلى طابق علوي الآن حالًا»." },
  { id:61, topic:"القسمة", emoji:"🍎",
    question:"هناك 10 تفاحات. إذا قسمتها بالتساوي على 5 أشخاص، كم تنال كل واحدة؟",
    choices:["تفاحة واحدة","تفاحتان","3 تفاحات","5 تفاحات"],
    answerIndex:1,
    explanation:"تقسيم الأشياء بالتساوي على الجميع هو فكرة «القسمة». لتقسيم 10 تفاحات بالتساوي على 5 أشخاص، أعطِ أولًا كل واحد تفاحة واحدة؛ بذلك تُستهلك 5 تفاحات. لا يزال لديك 5 تفاحات، فيمكنك أن تعطي كل واحد تفاحة أخرى. الآن نفدت كل التفاحات الـ10، ولدى كل شخص «تفاحتان». وحتى لا ينال أحد أكثر بينما يحزن آخر لأنه نال أقل، فإن حكمة العدّ بعناية والتقسيم بعدل قوة مهمة جدًا للعيش معًا في سلام." },
  { id:62, topic:"الضرب", emoji:"🍬",
    question:"تشتري 3 حلويات، كل واحدة بـ5 عملات. كم تدفع في المجموع؟",
    choices:["5 عملات","8 عملات","15 عملة","20 عملة"],
    answerIndex:2,
    explanation:"الحساب الذي يتكرّر فيه العدد نفسه مرّة بعد مرّة يُسمّى «الضرب». ثلاث حلويات بـ5 عملات لكل واحدة يعني أن 5 تُجمع ثلاث مرّات. 5 زائد 5 يساوي 10، وبإضافة 5 أخرى نحصل على 15 في المجموع. عند التسوّق، إذا لم تعرف هذا الحساب، فقد يأخذون منك أكثر مما يجب ويخدعونك دون أن تنتبه. ومعرفة كيف يجمع الضرب العدد نفسه دفعة واحدة تصبح سلاحًا قويًا لحماية مالك الثمين والبيع والشراء والعيش بشكل صحيح." },
  { id:63, topic:"الطرح (الباقي)", emoji:"🪙",
    question:"تذهب إلى الدكّان ومعك 10 عملات وتشتري سمكة بـ7 عملات. كم يكون الباقي (المال الذي يُعاد إليك)؟",
    choices:["عملتان","3 عملات","5 عملات","7 عملات"],
    answerIndex:1,
    explanation:"أن تطرح ما أنفقته من المجموع الذي معك يُسمّى «الطرح». عندما تدفع للبائع 7 عملات من أصل 10، لتعرف ما تبقّى تطرح 7 من 10. وبالعدّ تنازليًا من 10 واحدًا واحدًا — 9، 8، 7، 6، 5، 4، 3 — يتبقّى 3. هذا المال المتبقّي يُسمّى «الباقي». وإذا لم تستطع حساب الباقي بنفسك بعد الشراء، فقد تخسر، مثلًا إذا أعادوا لك باقيًا أقل مما يجب. إتقان الطرح هو الخطوة الأولى للعيش باستقلال دون أن تُخدَع في المجتمع." },
  { id:64, topic:"العدّ بالمكافئ", emoji:"📦",
    question:"تُحمّل البضاعة على عربة. وزن الصندوق الواحد يساوي 3 أحجار صغيرة. إذا كان هناك 3 صناديق، فكم حجرًا تساوي في المجموع؟",
    choices:["3 أحجار","6 أحجار","9 أحجار","12 حجرًا"],
    answerIndex:2,
    explanation:"هذه حكمة استبدال الوزن الكلّي بمقياس آخر — هنا عدد الأحجار. الصندوق الواحد هو 3 أحجار، فثلاثة صناديق تعني «ثلاث مجموعات من 3 أحجار». 3 زائد 3 يساوي 6، وبإضافة 3 أخرى يصبح 9. عندما تستطيع أن تحسب لا عدد الأشياء التي تراها فقط، بل «كم تزن في الحقيقة» باستبدالها بشيء آخر، يمكنك أن تمنع العربة من الكسر بسبب الحمل الزائد وأن تنقل الأشياء بتخطيط دون أن تُرهق ثورًا أو حصانًا." },
  { id:65, topic:"قاعدة التتابع", emoji:"🔷",
    question:"لغز نمط. «دائرة، مثلث، مربع، دائرة، مثلث، مربع، دائرة، مثلث» — ما الشكل التالي؟",
    choices:["دائرة","مثلث","مربع","علامة X"],
    answerIndex:2,
    explanation:"هذا لغز لإيجاد «القاعدة (النمط)» في طريقة ترتيب الأشياء. وبالنظر إلى الترتيب بعناية، ترى أن ثلاثة أشكال — دائرة، مثلث، مربع — تتكرّر بالترتيب نفسه مرّة بعد مرّة. عندما تنتهي مجموعة «دائرة، مثلث، مربع»، تبدأ التالية «دائرة، مثلث، مربع». واللغز يتوقف عند «دائرة، مثلث»، فبحسب القاعدة لا بدّ أن يكون التالي «مربع». حتى في عالم يبدو عشوائيًا، كثيرًا ما تكشف الملاحظة الدقيقة قواعد مخفية. وتنمية قدرة الدماغ هذه على إيجاد الأنماط تجعلك أفضل بكثير في توقّع المستقبل والتخطيط له." },
  { id:66, topic:"المنطق", emoji:"📏",
    question:"هناك 3 عصيّ مختلفة الطول (أ، ب، ج). أ أطول من ب. ب أطول من ج. أي عصا هي الأطول؟",
    choices:["العصا أ","العصا ب","العصا ج","كلها بالطول نفسه"],
    answerIndex:0,
    explanation:"هذا لغز «تفكير منطقي» تنظّم فيه المعلومات في رأسك لتصل إلى الجواب الصحيح. أولًا، من «أ أطول من ب» نعرف أن أ فوق ب. ثم من «ب أطول من ج» نعرف أن ب فوق ج. وبربط هذا في خطّ عمودي يكون الترتيب: أ في الأعلى، ب في الوسط، ج في الأسفل. إذن الأطول هي «العصا أ». وحتى دون وجود الأشياء الحقيقية أمامك، فإن قدرة تركيب الكلمات والشروط لإيجاد الجواب الصحيح مفيدة جدًا لإيجاد سبب المشكلة وحلّها بذكاء." },
  { id:67, topic:"ذكاء التقسيم", emoji:"🍞",
    question:"لغز عن تقسيم الطعام بالتساوي. لتقسيم رغيف خبز مستدير إلى أجزاء متساوية لـ«4 أشخاص»، كم قطعًا مستقيمًا بالسكين تحتاج؟",
    choices:["قطع واحد","قطعان","3 قطوع","4 قطوع"],
    answerIndex:1,
    explanation:"هذه حكمة «إدراك المكان» — تقسيم شكل في رأسك. اقطع الرغيف المستدير أولًا من المنتصف مستقيمًا «مرّة واحدة»، فينقسم إلى نصفين. ثم اقطع «القطع الثاني» مستقيمًا من المنتصف متقاطعًا مع الأول كعلامة زائد، فينقسم الخبز بدقّة إلى 4 قطع متساوية. بحركتين فقط من السكين يمكنك تقسيمه بالتساوي على 4 أشخاص. ومعرفة خصائص الأشكال هكذا تتيح لك تقسيم الأشياء بكفاءة وعدل، دون جهد ضائع ودون أن يستاء أحد." },
  { id:68, topic:"الضرب", emoji:"🐟",
    question:"تبيع السمك مقابل المال. بيع سمكة واحدة يعطي عملتين. إذا بعت 5 أسماك، كم عملة تكسب في المجموع؟",
    choices:["عملتان","5 عملات","7 عملات","10 عملات"],
    answerIndex:3,
    explanation:"هذا هو الضرب، أساس التجارة. تحصل على عملتين لكل سمكة، فبيع 5 أسماك يعني أن عملتين تجمّعتا 5 مرّات. وبالعدّ اثنين اثنين — 2، 4، 6، 8، 10 — نحصل على 10 عملات في المجموع. عندما تعمل بجدّ أو تبيع ما زرعته، إذا لم تستطع أن تحسب بشكل صحيح «كم ينبغي أن يكون المبلغ»، فقد يخفض تاجر سيّئ السعر ويستغلّك، تاركًا لك مالًا أقل بكثير من قيمة عملك. القدرة على حساب الأعداد درع يحمي قيمة عملك ويتيح لك عيشًا أكثر رخاءً." },
  { id:69, topic:"خانة العشرات", emoji:"🔟",
    question:"لغز عن مجموعات العشرة. هناك صناديق، يحمل كل واحد «مجموعة» من 10. إذا كان لديك 3 من هذه الصناديق و5 قطع مفردة، فكم لديك في المجموع؟",
    choices:["8","15","35","53"],
    answerIndex:2,
    explanation:"الأعداد التي نستخدمها كل يوم تتبع قاعدة تُسمّى «النظام العشري»، حيث تنتقل الـ10 المجتمعة إلى الخانة الأكبر التالية. ثلاثة صناديق من 10 تعني 10، 20، 30 — هذا وحده 30. وبإضافة الـ5 المفردة، 30 زائد 5 يساوي 35. في كثير من لغات وتجارات العالم، تُعدّ الأشياء والمال بهذه «المجموعات من عشرة». وحالما تستطيع أن تتخيّل في رأسك كيف تعمل الصناديق (العشرات) والقطع المفردة (الآحاد)، تصبح حتى الأعداد الأكبر مثل 100 أو 1000 سهلة العدّ." },
  { id:70, topic:"الحساب على خطوات", emoji:"🥚",
    question:"في سلّة 8 بيضات. تستخدم 3 للطبخ. بعد ذلك تبيض دجاجة بيضتين جديدتين. كم بيضة في السلّة الآن؟",
    choices:["3","5","7","10"],
    answerIndex:2,
    explanation:"هذا لغز تجري فيه حسابًا من «خطوتين» بالترتيب: ينقص العدد أولًا ثم يزيد. أولًا، اطرح 3 بيضات استُخدمت للطبخ من الـ8 في البداية. 8 ناقص 3 يساوي 5، وعند هذه النقطة في السلّة 5. ثم تبيض الدجاجة بيضتين جديدتين تُضافان إلى السلّة، فالآن أضف 2 إلى 5. 5 زائد 2 يساوي 7. في الحياة اليومية تحدث كل يوم تغيّرات معقّدة مثل «النقصان ثم الزيادة». وعندما تستطيع ترتيب الأحداث بالترتيب في رأسك ودمج الجمع والطرح، تصبح بارعًا جدًا في إدارة طعام بيتك والتخطيط له." },
  { id:71, topic:"الضِّعف", emoji:"🪣",
    question:"في الدلاء ماء. الدلو أ يتّسع لـ«ضعف» ما يتّسع له الدلو ب. الدلو ب يتّسع لـ4 لترات من الماء. كم لترًا يتّسع له الدلو أ؟",
    choices:["2 لتر","4 لترات","6 لترات","8 لترات"],
    answerIndex:3,
    explanation:"«ضعف» عدد يعني أن تضمّ إليه واحدًا آخر مثله؛ أي «جمعه مرّتين» أو «ضربه في 2». الدلو ب فيه 4 لترات، وأ ضعفه، فتخيّل جزأين من 4 لترات. وبحساب 4 زائد 4 نحصل على 8. لذلك يتّسع الدلو أ لـ8 لترات. في الحياة كثيرًا ما نقول «ضعف المساحة» و«ضعف الوزن» و«ضعف عدد الناس»، ومعرفة فكرة «الضِّعف» تتيح لك مقارنة الكميات بدقّة وتقدير الأدوات أو الماء التي يحتاجها العمل بشكل صحيح." },
  { id:72, topic:"الترتيب", emoji:"🧒",
    question:"5 أطفال يقفون في صفّ مستقيم. خلف الطفل الثالث من الأمام، كم طفلًا يقف؟",
    choices:["طفل واحد","طفلان","3 أطفال","4 أطفال"],
    answerIndex:1,
    explanation:"هذا لغز منطقي عن الفهم الصحيح للعلاقة بين العدد الكلّي والموضع في الوسط. هناك 5 أطفال في المجموع. وبالعدّ من الأمام — الأول، الثاني، الثالث — يشمل ذلك 3 أطفال، بمن فيهم الثالث نفسه. وبطرح هذه الـ3 من المجموع 5 يتبقّى 2. أي خلف الطفل الثالث يقف الرابع والخامس — «طفلان». والقدرة على إدراك الترتيب والموضع بدقّة بالأعداد حكمة مهمة عندما تصطفّ في جماعة لتنال شيئًا، أو لتحفظ دورك بعدل في المجتمع." },
  { id:73, topic:"قاعدة الأشكال", emoji:"🔺",
    question:"لغز عن خصائص الأشكال. أي شكل يمكنك تكوينه بوصل «3 عصيّ مستقيمة» دون فراغات؟",
    choices:["دائرة","مثلث","مربع","نجمة"],
    answerIndex:1,
    explanation:"هذا لغز عن القواعد الأساسية لتكوين الأشكال. باستخدام 3 عصيّ مستقيمة (أضلاع) ووصل أطرافها دون فراغات، تكوّن دائمًا «مثلثًا» بثلاث زوايا. وبأربع عصيّ تحصل على مربع، والدائرة مصنوعة من خطّ منحنٍ لا من عصيّ مستقيمة. وكما تعلّمنا في حزمة الميكانيكا السابقة، المثلث أقوى شكل في العالم — لا يتشوّه أبدًا تحت قوة من الأعلى. ومعرفة العلاقة بين عدد العصيّ والشكل هي أساس بناء بيوت متينة وتصميم دعائم آمنة للأشياء." },
  { id:74, topic:"قاعدة الأعداد", emoji:"🔢",
    question:"لغز عن كيفية تزايد الأعداد. مرتّبة «2، 4، 6، 8، 10». بحسب هذه القاعدة، ما العدد الذي يأتي بعد 10؟",
    choices:["11","12","13","15"],
    answerIndex:1,
    explanation:"هذه رياضة للعقل لإيجاد «القاعدة (المتتالية)» التي تتزايد فيها الأعداد بمقدار ثابت. وبالنظر بعناية، من 2 إلى 4 يزيد «2». ومن 4 إلى 6 يزيد «2» أيضًا. إذن هذا الصفّ من الأعداد يتبع قاعدة «الزيادة 2 في كل خطوة». ولإيجاد العدد بعد 10، فقط أضف «2» القاعدة إلى 10، فيكون 10 زائد 2 يساوي 12. وعندما تستطيع أن تدرك القوانين التي تزيد فيها الأعداد أو تنقص بقاعدة ثابتة، يصبح من السهل جدًا توقّع نموّ نبتة كل يوم أو فهم قواعد التواريخ في التقويم." },
  { id:75, topic:"النصف", emoji:"🫘",
    question:"تريد توزيع الفاصوليا التي حصدتها من حقلك على سلّتين، «العدد نفسه في كل واحدة»، إلى نصفين تمامًا. إذا كان هناك 12 حبّة فاصوليا في المجموع، فكم تضع في كل سلّة؟",
    choices:["4 في كل سلّة","6 في كل سلّة","8 في كل سلّة","12 في كل سلّة"],
    answerIndex:1,
    explanation:"تقسيم عدد إلى كميّتين متساويتين تمامًا يُسمّى «النصف». إذا وزّعت 12 حبّة فاصوليا على سلّتين واحدة واحدة بالتناوب، تنال كل سلّة العدد نفسه من الفاصوليا. وعند الانتهاء من توزيعها كلها والعدّ، تجد في كل سلّة «6 حبّات» تمامًا. وبما أن 6 زائد 6 يساوي 12، فنصف 12 هو 6. وعندما تتشارك الطعام أو المحصول مع العائلة والأصدقاء، فإن معرفة حساب النصف حكمة لطيفة تمنع الخصام وتتيح التقاسم بعدل، مع رعاية بعضكم بعضًا." },
  { id:76, topic:"التوازن", emoji:"⚖️",
    question:"لغز لمقارنة الأوزان. على الكفّة اليسرى لـ«الميزان» تضع تفاحة واحدة، فيتوازن تمامًا عندما تكون على الكفّة اليمنى 4 أحجار صغيرة. لمساواة وزن تفاحتين، كم حجرًا تحتاج في المجموع؟",
    choices:["2 حجر","4 أحجار","6 أحجار","8 أحجار"],
    answerIndex:3,
    explanation:"هذه حكمة حساب توازن الأوزان (النسبة). وزن تفاحة واحدة يساوي تمامًا وزن 4 أحجار. فماذا يحدث عندما يصبح عدد التفاح 2؟ بما أن التفاح تضاعف، فإن عدد الأحجار اللازمة لموازنته يجب أن يتضاعف أيضًا، وإلا اختلّ التوازن. أي تحتاج مجموعة أخرى مثل الـ4 أحجار. وبحساب 4 زائد 4، أو 4 في 2، يكون الجواب 8. وعند البيع والشراء، فإن القدرة على الوزن والمقارنة بشكل صحيح معرفة مهمة جدًا لتجنّب أن تُخدَع بكمية قليلة ظلمًا." },
  { id:77, topic:"كشف الكذب", emoji:"🧩",
    question:"لغز منطقي لإيجاد من يكذب. هناك شخصان، أ و ب. يقول أ: «أنا لا أكذب». ويقول ب: «أ يكذب». إذا كان ما يقوله أ [صحيحًا]، فهل ب يكذب أم يقول الصدق؟",
    choices:["ب يكذب","ب يقول الصدق","كلاهما يكذب","لا يمكن التحديد"],
    answerIndex:0,
    explanation:"هذا لغز منطقي متقدّم قليلًا لإيجاد تناقض في الكلام. شرط اللغز ينصّ على أن «ما يقوله أ صحيح». وهذا يعني أن أ شخص صادق لا يكذب حقًا. ومع ذلك يقول ب: «أ يكذب». وبما أن ب يتّهم أ الصادق بالكذب، فإن كلام ب هو «الخطأ (الكذب)». لذلك فالجواب الصحيح «ب يكذب». في المجتمع، القدرة على أن ترتّب في رأسك أيّ كلام صحيح وأيّه يناقض الحقائق مهمة جدًا لحماية نفسك." },
  { id:78, topic:"شراء موفّر", emoji:"🪵",
    question:"لغز لمقارنة الأوفر. يبيع الدكّان حزمتين من الحطب. الحزمة أ فيها «5 أعواد بـ10 عملات». الحزمة ب فيها «3 أعواد بـ10 عملات». إذا دفعت الـ10 عملات نفسها، فأيّهما يعطيك حطبًا أكثر وأوفر؟",
    choices:["الحزمة أ","الحزمة ب","كلاهما سواء","كلاهما خسارة"],
    answerIndex:0,
    explanation:"هذه قصة تسوّق عن المقارنة الذكية لـ«الكمية» التي تنالها بالسعر نفسه. كلتا أ و ب تكلّفان «10 عملات» تمامًا. لكن اختيار أ يعطيك 5 أعواد، بينما اختيار ب يعطيك 3 فقط. وبمقارنة 5 و3، فإن 5 أكثر بـ2، فبالمال نفسه يعطيك شراء أ حطبًا أكثر وهو «أوفر». والقدرة على أن تحكم بنفسك أيّهما ربح وأيّهما خسارة بمقارنة الأعداد عند الشراء حكمة عظيمة لاستخدام مالك ومواردك المحدودة بعناية وجعل حياتك أكثر رخاءً." },
  { id:79, topic:"كم يلزم بعد", emoji:"🏺",
    question:"هناك جرّة ماء كبيرة. تتّسع تمامًا لـ«5 دلاء» من الماء. الآن في الجرّة دلوان من الماء بالفعل. لملء الجرّة تمامًا، كم دلوًا من الماء تحتاج أن تضيف بعد؟",
    choices:["دلوان","3 دلاء","5 دلاء","7 دلاء"],
    answerIndex:1,
    explanation:"هذا تطبيق للطرح — حساب كم يلزم بعد (الفرق) للوصول إلى كمية مستهدفة. المجموع لملء الجرّة هو 5 دلاء. وبما أن دلوين في الداخل بالفعل، لإيجاد الفراغ المتبقّي اطرح الـ2 الحاليين من المجموع 5. وبحساب 5 ناقص 2 يكون الجواب 3. أي بإضافة 3 دلاء أخرى تملأ الجرّة تمامًا دون أن تفيض. في الطبخ والزراعة والعمل، فإن القدرة على أن تحسب بدقّة «كم يلزم بعد» نحو الهدف حكمة ضرورية لتجنّب الهدر والاستعداد بكفاءة." },
  { id:80, topic:"السرعة", emoji:"⏱️",
    question:"لغز لمقارنة الأزمنة. ثلاثة أصدقاء — أ و ب و ج — أجروا سباقًا. الزمن الذي استغرقه كل واحد للوصول إلى النهاية: أ 10 ثوانٍ، ب 8 ثوانٍ، ج 12 ثانية. من كان «الأسرع»؟",
    choices:["أ","ب","ج","الجميع بالسرعة نفسها"],
    answerIndex:1,
    explanation:"هذا لغز منطقي للفهم الصحيح لما تعنيه أعداد الزمن. في السباق، أن تكون «سريعًا» يعني أن «تستغرق أقلّ زمن (أصغر عدد)» للوصول إلى النهاية. ومن يستغرق زمنًا كثيرًا فقد ركض أبطأ بذلك القدر. وبمقارنة الأزمنة الثلاثة — 12، 10، 8 ثوانٍ — أصغر عدد هو «8 ثوانٍ» لـب. أي بما أن ب وصل إلى النهاية في أقلّ زمن، فقد كان الأسرع. وفهم الحالات التي لا يعني فيها العدد الأكبر الفوز خطوة تفكير مهمة أيضًا في الحساب والحياة اليومية." },
  { id:81, topic:"اكتشاف النار", emoji:"🔥",
    question:"عندما تعلّم البشر القدماء استخدام «النار» جيدًا، ما الذي أصبح أكثر أمانًا في حياتهم؟",
    choices:["استطاعوا الرؤية بعيدًا حتى في ظلام الليل","بشيّ اللحم والسمك لأكله، منعوا أمراض البطن واستطاعوا حماية أنفسهم من الوحوش","استطاعوا غسل ملابسهم حتى تنظف","استطاعوا الركض أسرع"],
    answerIndex:1,
    explanation:"بالنسبة للبشر القدماء، كان اكتشاف النار وتعلّم التحكّم بها بحرّية أعظم تقدّم لحماية الحياة. فاللحم والنباتات، القاسية والمليئة بالجراثيم وهي نيئة، يمكن تحويلها إلى طعام طريّ سهل الهضم وآمن لا يؤذي البطن، بـ«تسخينها (طهيها)» على النار. كما أنه بإبقاء نار متّقدة في ظلام الليل، تخاف الوحوش المرعبة التي تهاجم البشر منها فتكفّ عن الاقتراب، فيستطيع الناس النوم باطمئنان ليلًا أيضًا. كانت النار أول وأفضل وسيلة دفاع للبشرية للبقاء حيّة في الطبيعة القاسية." },
  { id:82, topic:"قوة الكتابة", emoji:"📜",
    question:"باختراع «الكتابة»، لماذا أصبحت مجتمعات العالم كله أكثر حكمة؟",
    choices:["يصل صوتك إلى شخص بعيد دون أن تتكلّم","دون الحاجة إلى حفظ كل شيء في الرأس فقط، أمكن نقل المعارف المهمة والقوانين (الاتفاقات) بدقّة إلى كثير من الناس لزمن طويل","صار الرسم غير ضروري تمامًا","كتابة الحروف تزيد المال من تلقاء نفسه"],
    answerIndex:1,
    explanation:"في العصر الذي سبق الكتابة، لم يكن أمام البشر إلا حفظ كل الحكمة والتاريخ ونقله «شفهيًا (بالحكايات)» فقط. لكن بهذه الطريقة قد يُنسى المضمون في منتصف الطريق أو يُنقل خطأً. وهنا اخترع البشر حكمة نقش «الكتابة» على ألواح الطين والحجر. وبذلك أمكنهم أن يتركوا لأحفادهم بعد مئات السنين، دون أدنى خطأ، أشياء مثل طريقة تمييز النباتات الآمنة، وقواعد المجتمع التي يجب أن يحفظها الجميع (القوانين)، وسجلّات أخطاء الماضي. الكتابة هي أعظم آلة زمن لمشاركة معرفة البشرية كلها وحفظها معًا، متجاوزةً حدود الذاكرة البشرية." },
  { id:83, topic:"العجلة", emoji:"🛞",
    question:"«العجلة (إطار مستدير)» المخترعة قديمًا — لماذا سهّلت تنقّل البشر وعملهم تسهيلًا هائلًا؟",
    choices:["الشكل المستدير يقلّل قوة الكبح (الاحتكاك) الناتجة عن الاحتكاك بالأرض، فتُدحرَج الأحمال الثقيلة وتُنقَل بقوة قليلة","تركيب العجلات يجعل الحمل يطفو في السماء","يتجمّع ماء كثير داخل العجلة","تبدو أظرف من الحمل المربّع"],
    answerIndex:0,
    explanation:"كما تعلّمنا في حزمة الميكانيكا السابقة، فإن جرّ شيء ثقيل مباشرة على الأرض يولّد كبحًا قويًا اسمه «الاحتكاك». لكن من تجربة «دحرجة جذع مستدير»، توصّل البشر إلى حكمة تركيب حلقة مستديرة دوّارة (عجلة) على العربة. وبتركيب العجلات، أمكن تحميل مئات الكيلوغرامات من الحطب والحجر والطعام التي لم يستطع تحريكها حتى 10 بالغين، على عربة ونقلها بسلاسة وبعيدًا بشخص واحد فقط. وبفضل اختراع العجلة استطاع البشر أن يتاجروا بكميات كبيرة من البضائع مع المدن البعيدة وأن يطوّروا مجتمعًا مزدهرًا." },
  { id:84, topic:"اختراع الورق", emoji:"📄",
    question:"«الورق» المخترع في الصين القديمة، كان رائعًا مقارنةً بالحجر وجلود الحيوانات وألواح الطين المستخدمة قبله. لماذا؟",
    choices:["خفيف جدًا ورقيق ويمكن طيّه، فأمكن صنع كميات كبيرة من الكتب بثمن رخيص وحملها","الورق لا يتمزّق أبدًا حتى لو ابتلّ","أكل الورق يملأ البطن","أصعب في النحت وأمتن من الحجر"],
    answerIndex:0,
    explanation:"قبل اختراع الورق، كان الناس يكتبون الحروف على «الحجر» أو «ألواح الطين» الثقيلة، أو على «جلود الحيوانات» الثمينة والغالية. وكانت أثقل من أن تُحمل بعيدًا، فلم يستطع قراءة الكتب إلا قلّة من ذوي المكانة أو الأغنياء. لكن عندما ظهر «الورق» — المصنوع بكبس ألياف النبات حتى تستوي وتتصلّب — أمكن صنع الكتب خفيفة على نحو مذهل ورقيقة ورخيصة وبكميات كبيرة. وبفضل ذلك وصلت معارف الأطباء وكتب المدارس إلى عامة الناس والأطفال في كل أنحاء العالم، وارتفع مستوى تعليم البشرية كلها وطبّها ارتفاعًا هائلًا." },
  { id:85, topic:"الزراعة", emoji:"🌾",
    question:"عندما انتقل البشر من حياة البحث عن الفريسة في الغابة إلى حرث الأرض وبدء «الزراعة»، كيف تغيّرت الحياة؟",
    choices:["دون السفر كل يوم إلى غابات بعيدة خطرة، استطاعوا البقاء في المكان نفسه (الاستقرار) وحصد طعام كثير باستقرار","بما أنهم لم يعودوا بحاجة للركض كل يوم، صغر جسد الجميع","لم يعودوا بحاجة للاهتمام بالطقس إطلاقًا","توقّفوا عن بناء البيوت وعادوا إلى الكهوف"],
    answerIndex:0,
    explanation:"قبل بدء الزراعة، كان البشر يلتقطون الثمار ويطاردون الحيوانات، مواصلين رحلة خطرة بالانتقال إلى المكان التالي عند نفاد الطعام. لكن باختراع «الزراعة» — بذر البذور والسقي وزراعة النبات بتخطيط — استطاع البشر بناء بيوت متينة و«الاستقرار» في مكان واحد. كما أنه بإمكان حصاد وتخزين كميات كبيرة من القمح والذرة دفعة واحدة، قلّ خطر الموت جوعًا، ووُضِع الأساس ليتعاون كثير من الناس ويبنوا قرى ومدنًا كبيرة ويعيشوا بأمان." },
  { id:86, topic:"بداية الملابس", emoji:"🧵",
    question:"لماذا بدأ البشر يصنعون «ملابسهم» بأنفسهم بغزل ألياف النبات وصوف الغنم؟",
    choices:["للتنافس في الجمال مع الأصدقاء والتخاصم","لحماية جلدهم وحرارة أجسامهم من الشمس القوية والبرد الشديد والعشب ذي الأشواك وسمّ الحشرات","لأنك لا تطفو على الماء دون ملابس","لإخفاء طعام كثير داخل الملابس"],
    answerIndex:1,
    explanation:"جلد الإنسان ليس له مخالب حادّة ولا فرو كثيف كالحيوان، لذا فهو رقيق جدًا وسهل الإصابة. غزل البشر الخيط ونسجوا «القماش» وصنعوا «الملابس» ليلفّوها حول الجسم، من أجل صنع درع دفاعي يحمي الحياة من الطبيعة القاسية. ارتداء الملابس يحمي حرارة الجسم من برد الشتاء القارس، ويمنع الحروق من شمس الصيف القوية، ويقي من أشواك العشب الحادّة ولدغات الحشرات الناقلة للأمراض مثل البعوض. الملابس «جلد ثانٍ» صنعه البشر بذكائهم، وأداة لا غنى عنها للتصرّف بأمان." },
  { id:87, topic:"المسكن", emoji:"🏠",
    question:"ما الهدف الأكبر من الخروج من الكهوف وبناء «بيت (مسكن)» بنفسك من الطين والخشب والحجر؟",
    choices:["لصنع غرف كثيرة ولعب الغمّيضة","لحماية حياة العائلة وممتلكاتها بثبات من المطر والريح والحرّ والبرد الشديدين، ومن الحيوانات البرّية التي تهاجم ليلًا","لحفر الأرض وصنع أقبية كثيرة","للتنافس في ارتفاع البيت والاقتراب من الآلهة"],
    answerIndex:1,
    explanation:"وضع نفسك في العراء مباشرةً يعرّضك باستمرار لأخطار مثل المطر المفاجئ الغزير، ورياح الليل المتجمّدة، والوحوش آكلة اللحوم التي تهاجم تحت ستار الظلام. بدأ البشر يصنعون الطوب بتجفيف الطين في الشمس ويبنون «بيوتًا (مساكن)» بجمع الخشب والحجر، ليغلقوا كل خطر من العالم الخارجي ويؤمّنوا فضاءً آمنًا. السقف يصدّ المطر والريح، والجدران والباب المتينة تبقي الأعداء في الخارج. وحكمة بناء «ملجأ آمن» بنفسك، حيث يمكنك النوم بعمق وإراحة جسد جريح أو مريض، حفظت حياة البشرية." },
  { id:88, topic:"أدوات الحديد", emoji:"⚒️",
    question:"بالانتقال من الأدوات الحجرية إلى أدوات «الحديد والمعدن» المصهورة في النار، ما الذي تقدّم؟",
    choices:["صارت الأدوات خفيفة وتطفو على الماء","بدلًا من أن تنكسر بسهولة كالحجر، أمكن صنع أدوات وآلات زراعية متينة جدًا وحادّة وطويلة العمر","الأدوات المعدنية تصير ذهبية إذا صُقلت","صارت الأدوات طريّة وتغيّر شكلها بحرّية"],
    answerIndex:1,
    explanation:"للفؤوس والسكاكين المصنوعة من الحجر نقطة ضعف: عند ضربها بقوة بشيء صلب، تتحطّم بسهولة إلى قطع. لكن البشر اكتشفوا أنه عند شيّ صخور معيّنة في نار شديدة الحرارة، يذوب من داخلها سائل لزج (معدن)، وعند تبريده يصبح أمتن بكثير من الحجر. كانت هذه بداية «البرونز» و«أدوات الحديد». أدوات الحديد لا تنكسر أبدًا حتى لو سقطت، وأتاحت قطع الأشجار الكبيرة القاسية وحفر الأرض الصلبة عميقًا لجعلها حقولًا. كانت ثورة رائعة في التقنية أتاحت أداء عمل أشدّ بأمان وبقوة أقل." },
  { id:89, topic:"السفينة الشراعية", emoji:"⛵",
    question:"عندما صنع البشر «السفينة الشراعية» برفع شراع كبير من القماش، كيف تغيّر التنقّل؟",
    choices:["دون التجديف بالذراعين، يلتقط الشراع «قوة الريح» من الطبيعة، فأمكنهم عبور البحر ونقل أحمال كبيرة إلى قارّات بعيدة","استطاعت السفينة الطيران في السماء تلقائيًا","لم تهتزّ السفينة أبدًا حتى لو جاءت عاصفة","استطاعوا تنقية ماء البحر وهم يتقدّمون"],
    answerIndex:0,
    explanation:"القوارب الصغيرة القديمة لم تكن تستطيع التقدّم إلا بالتجديف بالذراعين. وبهذه الطريقة تصل قوة الإنسان سريعًا إلى حدّها، وكان عبور بحر واسع بأمواج قوية مستحيلًا. لذلك اخترع البشر «السفينة الشراعية»، برفع جدار كبير من القماش (شراع) على السفينة لالتقاط «طاقة الريح» التي تهبّ فوق الأرض والتقدّم. وباستخدام قوة ريح الطبيعة بدل عضلات الإنسان، استطاعوا السفر بأمان دون راحة أيامًا، حاملين أطنانًا من الطعام والمؤن الثقيلة، إلى بلدان على بعد آلاف الكيلومترات عبر البحر، وتبادل حكمة بعضهم وثقافتهم." },
  { id:90, topic:"الساعات والوقت", emoji:"🕰️",
    question:"لماذا بدأ البشر يقيسون «الساعات والوقت» بدقّة باستخدام ظلّ الشمس المتحرّك (المزولة) وجريان الماء؟",
    choices:["ليتمكّن الجميع من الإسراع والركض","لمواءمة اتفاقات المجتمع بدقّة بين الجميع، مثل «متى نجتمع» و«متى نتناوب»، وخطط العمل","ليقرّروا بأنفسهم متى يجوعون","ليُجبروا الليل على أن يصير نهارًا"],
    answerIndex:1,
    explanation:"في عالم يكون فيه الوقت متناثرًا وغير موحّد، حتى مع وجود كثير من الناس، لا يثبت اتفاق على التعاون مثل «نجتمع في ذلك المكان ظهرًا ونرفع الجذع الثقيل معًا». فيأتي بعضهم مبكّرًا جدًا ويتأخّر آخرون، ويصير الأمر غير فعّال جدًا. اخترع البشر «الساعة» وبدؤوا يقسّمون اليوم إلى صباح وظهر وليل، وإلى ساعات — مجموعة أعداد مشتركة — تحديدًا ليجعلوا «اتفاقات (تزامن المجتمع)» المجتمع دقيقة. وبذلك أمكنهم تحديد أوقات تناوب العمل بعدل ووضع خطط للعودة إلى البيت بأمان قبل حلول الليل الخطر، مواءمين أفعال الجميع بلطف." },
  { id:91, topic:"التقويم", emoji:"📅",
    question:"صنع «تقويم» بمراقبة حركة النجوم والشمس — لماذا كان مهمًا للزراعة إلى حدّ أن الأرواح تتوقّف عليه؟",
    choices:["لأن تقليب التاريخ كل يوم ممتع","لتوقّع موعد «موسم المطر» أو «الشتاء القارس» مسبقًا، وبذر البذور في الوقت الصحيح، وتجهيز الطعام","لأنك تنال قدرة تغيير الطقس بحرّية بنفسك","لأن النظر إلى التقويم يجعل النبتة أمامك تنمو أسرع"],
    answerIndex:1,
    explanation:"في الزراعة، الخطأ في توقيت بذر البذور يعني أن يصير الحصاد صفرًا وتموت القرية كلها جوعًا. فإذا بذرت قبيل الشتاء، يذبل كل شيء من البرد. قديمًا، لاحظ الناس أن أنماط النجوم المتلألئة في سماء الليل، وموضع شروق الشمس، تتغيّر بقاعدة ثابتة ومنتظمة على مدار السنة. وتلخيص دورة الأرض هذه على ورق هو «التقويم». وباستخدامه، حتى وهو لا يزال دافئًا، أمكنهم قراءة المستقبل — «ينتهي موسم المطر بعد أسابيع قليلة، فابذر الآن» — وإنتاج الطعام بأمان، مستفيدين من خيرات الطبيعة إلى أقصى حدّ." },
  { id:92, topic:"بداية المال", emoji:"💰",
    question:"ما فائدة التوقّف عن مبادلة الأشياء بالأشياء مباشرةً (المقايضة) والبدء باستخدام «المال (العملة)» من الأصداف أو المعدن؟",
    choices:["لأن امتلاك المال يجعل اللصوص يكفّون عن مهاجمتك","حتى بين شخصين «يريدان أشياء مختلفة»، كصاحب السمك وصاحب اللحم، فإن وضع المال في الوسط يتيح لهما التبادل بعدل بما يريدان في أي وقت","لأن أكل المال يصير غذاءً","لأن المال متناثر في كل مكان بلا نهاية"],
    answerIndex:1,
    explanation:"في حياة «المقايضة»، حتى لو أردت مبادلة سمكك بملابس أحدهم، لا تتمّ الصفقة ما لم يكن ذلك الشخص يريد السمك. كما أن السمك يفسد سريعًا، فلا يمكنك حفظ قيمته. لذلك صنع البشر أداة مشتركة يعترف الجميع بقيمتها: «المال (العملة)». فإذا حوّلت السمك إلى مال مرّة، أمكنك حفظه دون أن يفسد، ثم في بلدة أخرى تشتري ملابس أو دواءً — ما تحتاجه، حين تحتاجه. نظام المال حكمة اقتصادية بديعة، اختُرعت ليتمكّن الناس في كل أنحاء العالم من مساعدة بعضهم (التبادل) بسلاسة وعدل دون عناء." },
  { id:93, topic:"الطباعة", emoji:"📚",
    question:"اختراع «طباعة الحروف المتحرّكة» — جمع الحروف واحدًا واحدًا لطباعة كميات كبيرة من الكتب — كيف غيّر العالم؟",
    choices:["زال عناء نسخ كل حرف باليد، وتضاعفت الكتب تضاعفًا هائلًا، ولم يعد الملوك وحدهم، بل أي أحد، يستطيع تعلّم المعرفة والعلم","صار وزن الكتب ثقيلًا كالحديد","وُحّدت كل حروف العالم في حرف واحد","بدأت الحروف المكتوبة في الكتب تتكلّم وحدها"],
    answerIndex:0,
    explanation:"قبل تقنية الطباعة، لصنع كتاب جديد، لم يكن أمام البشر إلا النظر بأعينهم إلى كل حرف و«نسخه باليد على ورق آخر (الاستنساخ)». وكان صنع كتاب واحد يستغرق أشهرًا، فكانت الكتب غالية كثمن بيت، ولم يستطع عامة الناس والأطفال حتى القراءة. «طباعة الحروف المتحرّكة»، التي طوّرها حرفيّون في ألمانيا وغيرها، تقنية تصفّ أختام حروف معدنية وتطبع صفحات كثيرة في لحظة بمكبس. وبذلك انخفض ثمن الكتب انخفاضًا حادًا، واستطاع أي أحد في العالم الحصول على «كتب الحكمة» في الطب والزراعة والحساب ليتعلّم — ثورة عظيمة قلّلت الخوف والمرض الناتجين عن الجهل." },
  { id:94, topic:"قنوات الماء", emoji:"🚰",
    question:"نظام «جرّ الماء (القناة)» المبني في روما القديمة وغيرها، الذي يجرّ الماء النظيف من نهر بعيد إلى المدينة — لماذا أنقذ أرواحًا كثيرة؟",
    choices:["لأنهم استطاعوا صنع برك نظيفة كثيرة داخل البيوت","لأن الناس لم يعودوا مضطرّين لشرب ماء وسخ مخلوط بالطين والجراثيم، فمنع ذلك الأوبئة المرعبة في المدينة كلها","لأن الاغتسال بماء الصنبور يشفي الجرح في الحال","لأنهم لم يعودوا بحاجة للسباحة إلى النهر للّعب"],
    answerIndex:1,
    explanation:"في المدن الكبيرة حيث يعيش الناس متزاحمين، تختلط القمامة والفضلات بسهولة بالآبار والأنهار القريبة، ويتّسخ الماء كثيرًا — مشكلة خطيرة. وشرب الماء الوسخ ينشر أوبئة مرعبة كالكوليرا في المدينة كلها في لحظة، فيحصد عشرات الآلاف من الأرواح. صنع البناؤون القدماء تقنية جرّ «ماء النبع النظيف الآمن» من جبال على بعد كيلومترات إلى المدينة عبر جسور حجرية (قنوات) بميل لطيف. وصنع بيئة يستطيع فيها الجميع دائمًا غسل أيديهم بماء نظيف وشرب ماء آمن صار أقوى درع يحمي حياة المدينة من المرض." },
  { id:95, topic:"المجهر", emoji:"🔬",
    question:"باختراع «المجهر»، وهو أداة تجمع عدسات زجاجية مستديرة، كيف تقدّم الأطباء والعلم؟",
    choices:["اكتشفوا شكل «الجراثيم (البكتيريا)» الصغيرة المسبّبة للمرض، غير المرئية إطلاقًا للعين البشرية، واستطاعوا العلاج والوقاية بشكل صحيح","صارت أشكال النجوم البعيدة مرئية بوضوح","أمكن حفظ الطعام داخل الزجاج","أمكن رؤية المنظر المحيط حتى والعينان مغمضتان"],
    answerIndex:0,
    explanation:"حتى المجهر، لم يكن البشر يعرفون الأسباب الحقيقية لمرض الناس أو لفساد الطعام. كان يُظنّ أنه بسبب أرواح شرّيرة أو لعنات غير مرئية، وفقد كثيرون أرواحهم بسبب علاج خاطئ. لكن باختراع «المجهر» الذي يكبّر العالم الصغير مئات المرّات بقوة العدسات، رأت البشرية أخيرًا بأمّ عينها الجاني الذي يفسد الماء ويسبّب المرض في الجسم: «الجراثيم والكائنات الدقيقة الصغيرة». وحالما عُرفت هوية العدوّ، بدأ تاريخ الطب الوقائي الصحيح الذي يحمي الحياة بثبات: «غلي الماء لتعقيمه»، «غسل اليدين»." },
  { id:96, topic:"البوصلة", emoji:"🧭",
    question:"«البوصلة»، التي تشير إبرتها المغناطيسية دائمًا إلى الشمال — كيف ساعد اختراعها من يسافرون في بحر الليل المظلم أو الصحراء؟",
    choices:["حتى في أماكن لا يُرى فيها المنظر المحيط إطلاقًا، تعرف «الاتجاه الصحيح» الذي تقصده وتتجنّب الضياع","بقوة المغناطيس صارت السفينة أسرع أضعافًا","نفخت كل رمل الصحراء وشقّت طريقًا نظيفًا","الإبرة تغيّر الطقس إلى صحو تلقائيًا"],
    answerIndex:0,
    explanation:"في «البحر المفتوح الواسع» أو «الصحراء التي لا نهاية لها»، حيث تبدو كل الجهات الـ360 درجة متشابهة، أو عند التنقّل في ضباب كثيف أو ليل حالك، يكون ذلك أخطر وأرهب وقت، حين تفقد الاتجاه الذي يجب أن تقصده. اكتشف البشر الخاصية العجيبة بأن إبرة مغناطيسية معيّنة «تشير دائمًا بثبات إلى الشمال» بفعل قوة الأرض المغناطيسية غير المرئية، وركّبوها في أداة. هذه هي البوصلة. وبحملها، حتى دون علامات طقس أو معالم، تعرف بدقّة 100% إن كنت تتّجه شرقًا أم غربًا، فأمكن تجنّب كارثة الضياع والهلاك عند نفاد الماء والطعام تمامًا." },
  { id:97, topic:"الكهرباء", emoji:"💡",
    question:"عندما طوّر البشر تقنية توليد «الكهرباء» وإرسالها عبر الأسلاك، كيف صارت حياة الناس الليلية أكثر أمانًا؟",
    choices:["بالمصابيح، أمكنهم إضاءة نور آمن ومشرق دون خطر إشعال حريق داخل الغرفة","قصُر الليل من تلقاء نفسه وجاء الصباح سريعًا","تدفّق ماء كثير من الأسلاك","صارت جدران البيت متينة كالحديد"],
    answerIndex:0,
    explanation:"قبل انتشار الكهرباء، كان النور الوحيد ليلًا هو «إشعال نار مباشرة» على الشموع أو الزيت أو الغاز. لذلك إن أوقعته الريح أو نُسي إطفاؤه، صار في لحظة حريقًا كبيرًا يلتهم البيت، وفقد كثيرون أرواحهم. كما أنه لخفوت النور، كان العمل ليلًا خطرًا جدًا. ومنذ أن حوّل البشر الطاقة إلى كهرباء وأضاؤوا «المصابيح»، أمكنهم الحصول على «نور آمن مشرق كالشمس» لا يصدر دخانًا ولا يسبّب حريقًا أبدًا حتى لو وقع، بضغطة زرّ واحدة. إنها تقنية عظيمة قلّلت بشدّة جرائم الليل وإصاباته وتحمي أمان المجتمع على مدار الساعة." },
  { id:98, topic:"الاتصالات", emoji:"📞",
    question:"عندما تقدّمت الاتصالات من «إشارات الدخان» و«الرسائل» إلى «التلغراف والهاتف» اللذين ينقلان الرسائل بإشارات كهربائية، ما الذي تحسّن أكثر من غيره؟",
    choices:["صار معنى الكلمات يتحوّل إلى الإنجليزية تلقائيًا","دون الركض أيامًا لاستدعاء أحد، أمكن نقل «خطر طارئ (SOS)» مثل مطر غزير أو زلزال إلى مدينة بعيدة في لحظة لطلب النجدة","الاتصال بالهاتف يجعل الأمتعة تطير أمامك","صار وزن صديقك أخفّ"],
    answerIndex:1,
    explanation:"عندما كانت كارثة كبيرة أو عدوّ يقترب من مدينة بعيدة، كانت الوسيلة الوحيدة قديمًا إطلاق حصان أو إرسال شخص يركض ليوصل رسالة، وهذا يستغرق أيامًا كثيرة، وكثيرًا ما كان الوقت قد فات عند الوصول. وباختراع «التلغراف» و«الهاتف» اللذين يحملان الكلمات والإشارات على موجات كهربائية، صار في وسع المعلومة أن تصل إلى الجانب الآخر من العالم بـ«سرعة هائلة كالضوء»، متجاوزةً سرعة أقدام البشر. وبذلك أمكن نقل نداء استغاثة منقذ للحياة — «الجبل على وشك الانهيار، اهرب الآن!»، «أحدهم أُصيب بجروح بالغة، أرسل طبيبًا!» — في ثانية واحدة، وازداد عدد الأرواح التي يمكن إنقاذها ازديادًا ساحقًا." },
  { id:99, topic:"تقدّم الطبّ", emoji:"💉",
    question:"عندما طوّر الأطباء طرق «الحقن (اللقاحات)» و«تعقيم الأدوات»، كيف حُمِيت حياة البشر؟",
    choices:["صارت عظام الإنسان صلبة كالمعدن","الأطفال الصغار وكثير من الناس الذين كانوا يموتون بسهولة لضعف أجسامهم، استطاعوا تجنّب الأمراض المرعبة والعيش طويلًا بصحّة","حتى عند الإصابة، لم يخرج دم إطلاقًا","هرب كل المرضى راكضين"],
    answerIndex:1,
    explanation:"قديمًا، مهما كان الشخص سليمًا، فبمجرّد أن يسمح جرح صغير بدخول الجراثيم، أو ينتشر فيروس مرعب كالجدري في القرية، ولعدم وجود دواء أو وقاية، كان كثيرون يفقدون أرواحهم صغارًا، عاجزين عن منع ذلك. اكتشف علماء الطبّ حكمة «اللقاحات (التطعيم)» — إدخال مكوّنات آمنة إلى الجسم مسبقًا لبناء حاجز ضدّ المرض — و«التعقيم»، بإبادة الجراثيم بالصابون والكحول. وبفضل هذه التقنية الطبية، قفز احتمال نجاة الرضّع والأطفال في كل أنحاء العالم بأمان حتى سنّ الرشد، دون أن يفقدوا أرواحهم في الطريق، أضعافًا كثيرة." },
  { id:100, topic:"معنى التعلّم", emoji:"🦉",
    question:"في هذا التطبيق «Wise World»، ما [الهدف الحقيقي] من أنك تعلّمت كل هذه الحكمة من العلم والتاريخ؟",
    choices:["أن تنال 100 في امتحان وتصير أعظم من الآخرين","أن تخزّن في رأسك أفضل تعويذة — الحكمة (المعرفة) — وتحمي حياتك وحياة من حولك، وتتعاون مع الجميع لبناء «عالم لطيف وآمن» والعيش فيه","أن تجمع مالًا كثيرًا وتعيش في رفاهية وحدك","أن تجمع نقاط خبرة الاختبار (EXP)، وتنهي اللعبة وتكتفي"],
    answerIndex:1,
    explanation:"تهانينا! بهذا يكتمل السؤال الـ100 الذي لا يُنسى. كل «الأدوات والعلم وحكمة التاريخ» التي راكمتها البشرية على مدى عشرات آلاف السنين، عبر إخفاقات متكرّرة وبمخاطرة بأرواحها، ليست موجودة لاضطهاد أحد ولا ليحتكر شخص واحد الامتيازات ويتباهى. إنها ثروة مشتركة، اختُرعت ليتمكّن البشر جميعًا — بمساعدة المحتاجين حقًا، وتجنّب الخطر، وعبور الحدود واللغات — من التحرّر من خوف المرض والجوع و«العيش بلطف وأمان وسعادة (الرعاية)». فلتُضِئ بلطف، وبوصلة الحكمة التي تعلّمتها في هذا التطبيق في قلبك، حياتك أنت ومستقبل العالم. العالم كله يشجّع رحلتك في التعلّم!" }
];
